function getAppUrl(req?: Request): string {
  if (req) {
    const origin = req.get('origin');
    if (origin && origin.startsWith('http')) return origin;
    const host = req.get('host');
    if (host) return `https://${host}`;
  }
  return 'https://www.licenseiq.ai';
}
