// Configure multer for secure file uploads with disk storage
const uploadDir = path.join(process.cwd(), 'uploads');
const upload = multer({
  storage: multer.diskStorage({
    destination: (req, file, cb) => {
      cb(null, uploadDir);
    },
    filename: (req, file, cb) => {
      // Generate secure filename with UUID
      const fileExtension = path.extname(file.originalname);
      const fileName = `${randomUUID()}${fileExtension}`;
      cb(null, fileName);
    },
  }),
  limits: {
    fileSize: 100 * 1024 * 1024, // 100MB limit
  },
  fileFilter: (req, file, cb) => {
    const allowedTypes = [
      'application/pdf',
      'application/msword',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
      'text/plain'
    ];
    if (allowedTypes.includes(file.mimetype)) {
      cb(null, true);
    } else {
      cb(new Error('Invalid file type. Only PDF, DOC, DOCX, and TXT files are allowed.'));
    }
  },
});

// Configure multer for CSV/Excel uploads
const dataUpload = multer({
  storage: multer.diskStorage({
    destination: (req, file, cb) => {
      cb(null, uploadDir);
    },
    filename: (req, file, cb) => {
      const fileExtension = path.extname(file.originalname);
      const fileName = `${randomUUID()}${fileExtension}`;
      cb(null, fileName);
    },
  }),
  limits: {
    fileSize: 50 * 1024 * 1024, // 50MB limit for data files
  },
  fileFilter: (req, file, cb) => {
    const allowedTypes = [
      'text/csv',
      'application/vnd.ms-excel',
      'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'
    ];
    const allowedExts = ['.csv', '.xlsx', '.xls'];
    const fileExt = path.extname(file.originalname).toLowerCase();
    
    if (allowedTypes.includes(file.mimetype) || allowedExts.includes(fileExt)) {
      cb(null, true);
    } else {
      cb(new Error('Invalid file type. Only CSV and Excel files are allowed.'));
    }
  },
});

// Audit logging middleware
async function createAuditLog(req: any, action: string, resourceType?: string, resourceId?: string, details?: any) {
  if (req.user?.id) {
    try {
      await storage.createAuditLog({
        userId: req.user.id,
        action,
        resourceType,
        resourceId,
        details,
        ipAddress: req.ip,
        userAgent: req.get('User-Agent') || '',
      });
    } catch (error) {
      console.error('Failed to create audit log:', error);
    }
  }
}

// Helper function to check if user is system admin
function isSystemAdmin(user: any): boolean {
  return user?.isSystemAdmin === true;
}

// Helper function to get user's company ID from active context
function getUserCompanyId(user: any): string | null {
  return user?.activeContext?.companyId || null;
}

// Helper function to check if user is admin/owner (for their context)
function isContextAdmin(user: any): boolean {
  const contextRole = user?.activeContext?.role;
  return contextRole === 'admin' || contextRole === 'owner';
}

// ----- Aggregation period helpers (rule editor + AI extraction) -----
// Map a human / AI aggregation-period label onto the canonical
// rules.aggregation_scope enum (per_sale / per_period / per_contract). Returns
// null when the input doesn't match a known period — caller decides whether
// to treat that as an error or leave NULL.
function deriveAggregationScopeFromPeriod(period: unknown): string | null {
  if (typeof period !== 'string') return null;
  const p = period.trim().toLowerCase();
  if (!p) return null;
  if (p === 'per_sale' || p === 'per-sale' || p === 'transaction' || p === 'sale') return 'per_sale';
  if (
    p === 'monthly' || p === 'month' ||
    p === 'quarterly' || p === 'quarter' ||
    p === 'annual' || p === 'annually' || p === 'year' || p === 'yearly' ||
    p === 'semi_annual' || p === 'semiannual' || p === 'semi-annual' ||
    p === 'weekly' || p === 'daily'
  ) return 'per_period';
  if (p === 'contract' || p === 'lifetime' || p === 'per_contract') return 'per_contract';
  return null;
}

// Rule types whose calc engine actually aggregates sales over a window
// (percentage rate × period totals, tier brackets against quarterly volume,
// minimums measured against annual totals, caps against period totals, …).
// For these, an aggregation period MUST be set — leaving it blank lets the
// engine silently fall back to per_sale and produces wrong results for
// quarterly / annual contracts.
const RULE_TYPES_REQUIRING_AGGREGATION_PERIOD = new Set([
  'percentage', 'category_percentage', 'rebate_percentage', 'rebate_rate',
  'tiered', 'rebate_tiered', 'milestone_tiered', 'rate_structure',
  'per_unit', 'formula_based',
  'minimum_guarantee', 'annual_minimum', 'quarterly_minimum', 'mgr',
  'cap', 'period_cap', 'contract_cap',
]);
function ruleTypeRequiresAggregationPeriod(ruleType: unknown): boolean {
  if (typeof ruleType !== 'string') return false;
  return RULE_TYPES_REQUIRING_AGGREGATION_PERIOD.has(ruleType.trim().toLowerCase());
}

