  // Lists every contract spawned from this template — used by the /templates
  // page to show a "Used by N contracts" badge with deep links into each
  // contract's analysis page. The link is stamped at create time into
  // contract_analysis.key_terms.sourceTemplateId, so no schema change is
  // required. Authorization mirrors the other library routes: anyone who can
  // see the template can see its usage; results are themselves tenant-scoped
  // so a user never learns about contracts in another org.
  app.get('/api/contract-templates/library/:templateId/usage', isAuthenticated, async (req: any, res: Response) => {
    try {
      const userId = req.user?.id ?? null;
      if (!userId) return res.status(401).json({ message: 'Not authenticated' });
      const callerCompanyId = req.user?.activeContext?.companyId || req.user?.companyId || null;
      // Only system admins (platform staff) bypass tenant filtering. Company
      // admins/owners are still scoped to their own tenant — system templates
      // are visible across orgs, so without this scoping a company admin
      // could enumerate contract names from other tenants by hitting this
      // endpoint with a system template id.
      const isSystemAdmin = req.user?.isSystemAdmin === true;

      const tpl = await getAuthorizedTemplate(req.params.templateId, userId, callerCompanyId);
      if (!tpl) return res.status(404).json({ message: 'Template not found' });

      type UsageRow = {
        id: string;
        display_name: string | null;
        original_name: string | null;
        contract_number: string | null;
        status: string | null;
        contract_status: string | null;
        company_id: string | null;
        uploaded_by: string | null;
        created_at: string | null;
      };
      // Latest contract_analysis row per contract wins — mirrors the lookup
      // in the per-contract sample download route. Tenant scoping is applied
      // in JS below so admins still get the full list.
      const rows = await db.execute<UsageRow>(sql`
        SELECT c.id,
               c.display_name,
               c.original_name,
               c.contract_number,
               c.status,
               c.contract_status,
               c.company_id,
               c.uploaded_by,
               c.created_at
        FROM contracts c
        JOIN LATERAL (
          SELECT key_terms
          FROM contract_analysis
          WHERE contract_id = c.id
          ORDER BY created_at DESC NULLS LAST
          LIMIT 1
        ) ca ON TRUE
        WHERE (ca.key_terms::jsonb ->> 'sourceTemplateId') = ${req.params.templateId}
        ORDER BY c.created_at DESC NULLS LAST
      `);

      const all = rows.rows ?? [];
      const visible = isSystemAdmin
        ? all
        : all.filter((r) => {
            // Same-tenant rows are always visible; un-tenanted rows fall back
            // to "uploader can see their own".
            if (r.company_id && callerCompanyId && r.company_id === callerCompanyId) return true;
            if (!r.company_id && r.uploaded_by === userId) return true;
            return false;
          });

      const contracts = visible.map((r) => ({
        id: r.id,
        displayName: r.display_name || r.original_name || r.contract_number || 'Untitled contract',
        contractNumber: r.contract_number,
        status: r.status,
        contractStatus: r.contract_status,
        createdAt: r.created_at,
      }));

      res.json({ templateId: req.params.templateId, count: contracts.length, contracts });
    } catch (error: any) {
      console.error('Error fetching template usage:', error);
      res.status(500).json({ message: error.message });
    }
  });

