  app.post('/api/contracts/:id/replace-pdf', isAuthenticated, upload.single('file'), async (req: any, res: Response) => {
    try {
      if (!req.file) {
        return res.status(400).json({ error: 'No file uploaded' });
      }
      const contractId = req.params.id;
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }

      const fs = await import('fs');
      if (contract.filePath && fs.existsSync(contract.filePath)) {
        try { fs.unlinkSync(contract.filePath); } catch (e) {}
      }

      // Reset all verified rules to under_review on PDF replacement
      console.log(`🔄 Resetting verified rules to under_review for contract ${contractId} (PDF replaced)`);
      await db.execute(sql`UPDATE contract_rules SET review_status = 'under_review', reviewed_at = NOW() WHERE contract_id = ${contractId} AND review_status = 'verified'`);

      await db.update(contracts).set({
        originalName: req.file.originalname,
        fileName: req.file.filename,
        fileSize: req.file.size,
        filePath: req.file.path,
        fileType: req.file.mimetype,
        displayName: contract.displayName || req.file.originalname,
      }).where(eq(contracts.id, contractId));

      res.json({ success: true, message: 'PDF replaced successfully', fileName: req.file.originalname, fileSize: req.file.size });
    } catch (error) {
      console.error('Replace PDF error:', error);
      res.status(500).json({ error: 'Failed to replace PDF' });
    }
  });

