  // Per-contract agent fleet status — feeds the agent peek + per-card pills
  // on the contract page. Reuses the same derivation logic as the global
  // /api/ingestion/inbox endpoint so the inbox and contract page can never
  // drift out of sync.
  app.get('/api/contracts/:id/agent-status', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { deriveContractAgentStatus } = await import('./services/agentFleet');
      const contract = await storage.getContract(req.params.id);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      const runs = await storage.getExtractionRunsByContract(req.params.id);
      // Runs come back ordered by createdAt DESC from storage; defensively pick
      // whichever has the latest createdAt in case a future change reorders.
      const latestRun = (runs || []).slice().sort((a: any, b: any) => {
        const ta = a?.createdAt ? new Date(a.createdAt).getTime() : 0;
        const tb = b?.createdAt ? new Date(b.createdAt).getTime() : 0;
        return tb - ta;
      })[0] || null;

      const agents = deriveContractAgentStatus({
        contractStatus: (contract as any).status,
        fileType: (contract as any).fileType,
        latestRun: latestRun
          ? {
              status: latestRun.status ?? null,
              currentStage: latestRun.currentStage ?? null,
              confidence: (latestRun as any).overallConfidence ?? null,
              rulesExtracted: (latestRun as any).rulesExtracted ?? null,
              errorLog: (latestRun as any).errorLog ?? null,
            }
          : null,
      });

      res.json({
        contractId: req.params.id,
        contractStatus: (contract as any).status || null,
        latestRun: latestRun
          ? {
              id: latestRun.id,
              status: latestRun.status,
              currentStage: latestRun.currentStage,
              createdAt: latestRun.createdAt,
              completedAt: (latestRun as any).completedAt ?? null,
            }
          : null,
        agents,
      });
    } catch (error: any) {
      console.error('Get agent status error:', error);
      res.status(500).json({ error: error.message || 'Failed to fetch agent status' });
    }
  });

