  // In-memory enrichment status tracking
  const enrichmentStatus: Map<string, { state: 'running' | 'completed' | 'failed'; total: number; processed: number; startedAt: number; error?: string }> = new Map();
  
  // Get enrichment status for a contract
  app.get('/api/contracts/:contractId/enrichment-status', isAuthenticated, async (req: any, res: Response) => {
    const { contractId } = req.params;
    const context = req.user?.activeContext;
    const userId = req.user?.id;
    
    // Multi-tenant authorization check
    const contract = await storage.getContract(contractId);
    if (!contract) {
      return res.status(404).json({ error: 'Contract not found' });
    }
    const userRole = (await storage.getUser(userId))?.role;
    const isAdmin = userRole === 'admin' || userRole === 'owner';
    if (!isAdmin && context?.companyId && contract.companyId !== context.companyId) {
      return res.status(403).json({ error: 'Access denied' });
    }
    
    const status = enrichmentStatus.get(contractId);
    if (!status) {
      return res.json({ state: 'idle', total: 0, processed: 0 });
    }
    res.json(status);
  });

  // On-demand AI enrichment with batching and progress tracking
  app.post('/api/contracts/:contractId/enrich-rules', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId } = req.params;
      const { ruleId } = req.body;
      const userId = req.user?.id;
      const context = req.user?.activeContext;
      
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      
      // Multi-tenant authorization check
      const userRole = (await storage.getUser(userId))?.role;
      const isAdmin = userRole === 'admin' || userRole === 'owner';
      if (!isAdmin && context?.companyId && contract.companyId !== context.companyId) {
        return res.status(403).json({ error: 'Access denied: Contract belongs to different organization' });
      }
      
      // Check if already running
      const existing = enrichmentStatus.get(contractId);
      if (existing?.state === 'running') {
        return res.json({ message: 'Enrichment already in progress', ...existing });
      }
      
      const savedRules = await storage.getRoyaltyRulesByContract(contractId);
      if (savedRules.length === 0) {
        return res.status(404).json({ error: 'No rules found for this contract' });
      }
      
      let rulesToEnrich = ruleId 
        ? savedRules.filter(r => r.id === ruleId)
        : savedRules;
      
      if (!ruleId) {
        const unenrichedRules = rulesToEnrich.filter(r => {
          const fd = r.formulaDefinition as any;
          if (!fd || typeof fd !== 'object') return true;
          return !(fd.logic || fd.category || fd.examples || fd.implementationChecklist);
        });
        if (unenrichedRules.length === 0) {
          enrichmentStatus.set(contractId, { state: 'completed', total: rulesToEnrich.length, processed: rulesToEnrich.length, startedAt: Date.now() });
          return res.json({ message: 'All rules already enriched', count: 0, alreadyEnriched: true });
        }
        rulesToEnrich = unenrichedRules;
      }
      
      if (rulesToEnrich.length === 0) {
        return res.status(404).json({ error: 'Rule not found' });
      }
      
      // Set status and respond immediately
      enrichmentStatus.set(contractId, { state: 'running', total: rulesToEnrich.length, processed: 0, startedAt: Date.now() });
      res.json({ message: `Enriching ${rulesToEnrich.length} rules in batches...`, count: rulesToEnrich.length });
      
      // Fire-and-forget batched enrichment
      const contractText = contract.rawText || '';
      const contractType = contract.contractType || undefined;
      const BATCH_SIZE = 5;
      
      const enrichInBackground = async () => {
        try {
          let totalEnriched = 0;
          
          for (let batchStart = 0; batchStart < rulesToEnrich.length; batchStart += BATCH_SIZE) {
            const batch = rulesToEnrich.slice(batchStart, batchStart + BATCH_SIZE);
            console.log(`📦 [Enrich] Processing batch ${Math.floor(batchStart / BATCH_SIZE) + 1}: rules ${batchStart + 1}-${batchStart + batch.length}`);
            
            const richFormulas = await groqService.generateRichFormulaDefinitions(batch, contractText);
            
            for (let i = 0; i < batch.length && i < richFormulas.length; i++) {
              if (richFormulas[i] && typeof richFormulas[i] === 'object') {
                try {
                  const existingFormula = batch[i].formulaDefinition as any || {};
                  const mergedFormula = { ...existingFormula, ...richFormulas[i] };
                  if (existingFormula.tableData && !richFormulas[i].tableData) mergedFormula.tableData = existingFormula.tableData;
                  if (existingFormula.calculation && !richFormulas[i].calculation) mergedFormula.calculation = existingFormula.calculation;
                  if (existingFormula.conditions && !richFormulas[i].conditions) mergedFormula.conditions = existingFormula.conditions;
                  
                  const updateData: any = { formulaDefinition: mergedFormula };
                  const existingMappings = batch[i].fieldMappings as any;
                  if (!existingMappings || Object.keys(existingMappings).length === 0) {
                    const autoMappings = await getAutoFieldMappings(mergedFormula, contractType);
                    if (autoMappings) updateData.fieldMappings = autoMappings;
                  }
                  await storage.updateRoyaltyRule(batch[i].id, updateData);
                  totalEnriched++;
                } catch (err) { /* skip individual failures */ }
              }
            }
            
            // Update progress after each batch
            enrichmentStatus.set(contractId, { state: 'running', total: rulesToEnrich.length, processed: totalEnriched, startedAt: enrichmentStatus.get(contractId)?.startedAt || Date.now() });
            console.log(`✅ [Enrich] Batch complete: ${totalEnriched}/${rulesToEnrich.length} enriched so far`);
          }
          
          enrichmentStatus.set(contractId, { state: 'completed', total: rulesToEnrich.length, processed: totalEnriched, startedAt: enrichmentStatus.get(contractId)?.startedAt || Date.now() });
          console.log(`✅ On-demand enrichment complete: ${totalEnriched}/${rulesToEnrich.length} rules enriched`);
          
          // Auto-cleanup status after 5 minutes
          setTimeout(() => enrichmentStatus.delete(contractId), 5 * 60 * 1000);
        } catch (err: any) {
          console.error(`❌ On-demand enrichment failed:`, err.message);
          enrichmentStatus.set(contractId, { state: 'failed', total: rulesToEnrich.length, processed: enrichmentStatus.get(contractId)?.processed || 0, startedAt: enrichmentStatus.get(contractId)?.startedAt || Date.now(), error: err.message });
          setTimeout(() => enrichmentStatus.delete(contractId), 5 * 60 * 1000);
        }
      };
      enrichInBackground();
    } catch (error: any) {
      console.error('Error enriching rules:', error);
      if (!res.headersSent) {
        res.status(500).json({ error: error.message || 'Failed to enrich rules' });
      }
    }
  });

  // Confirm a fee rule (human-in-the-loop approval)
  app.patch('/api/royalty-rules/:id/confirm', isAuthenticated, async (req: any, res: Response) => {
    try {
      const ruleId = req.params.id;
      const userId = req.user?.id;
      const context = req.user?.activeContext;
      
      // Get the rule first to verify ownership
      const [rule] = await db
        .select()
        .from(contractRules)
        .where(eq(contractRules.id, ruleId))
        .limit(1);
      
      if (!rule) {
        return res.status(404).json({ error: 'Rule not found' });
      }
      
      // Get the contract to check multi-tenant authorization
      const contract = await storage.getContract(rule.contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      
      // Multi-tenant authorization check
      const userRole = (await storage.getUser(userId))?.role;
      const isAdmin = userRole === 'admin' || userRole === 'owner';
      if (!isAdmin && context?.companyId && contract.companyId !== context.companyId) {
        return res.status(403).json({ error: 'Access denied: Rule belongs to different organization' });
      }
      
      // Update the rule's review status to confirmed
      await db
        .update(contractRules)
        .set({
          reviewStatus: 'confirmed',
          reviewedBy: userId,
          reviewedAt: new Date(),
          updatedAt: new Date()
        })
        .where(eq(contractRules.id, ruleId));
      
      console.log(`✅ Rule ${ruleId} confirmed by user ${userId}`);
      res.json({ success: true, message: 'Rule confirmed successfully' });
    } catch (error: any) {
      console.error('Confirm rule error:', error);
      res.status(500).json({ error: error.message || 'Failed to confirm rule' });
    }
  });

  app.patch('/api/contracts/:contractId/rules/bulk-review-status', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId } = req.params;
      const { reviewStatus, ruleIds } = req.body;
      const validStatuses = ['pending', 'under_review', 'verified', 'rejected'];
      if (!validStatuses.includes(reviewStatus)) {
        return res.status(400).json({ message: `Invalid review status` });
      }
      const updateData: any = {
        reviewStatus,
        reviewedBy: req.user?.id || null,
        reviewedAt: new Date(),
        updatedAt: new Date(),
      };
      let condition = eq(contractRules.contractId, contractId);
      if (ruleIds && Array.isArray(ruleIds) && ruleIds.length > 0) {
        condition = and(condition, inArray(contractRules.id, ruleIds))!;
      }
      const updated = await db.update(contractRules)
        .set(updateData)
        .where(condition)
        .returning();
      try {
        const { revertContractApprovalIfRulesIncomplete } = await import("./services/contractApprovalIntegrity");
        await revertContractApprovalIfRulesIncomplete(contractId, `Bulk rule review status set to '${reviewStatus}'`);
      } catch (revertErr) {
        console.error("[contractApprovalIntegrity] bulk-review-status revert failed:", revertErr);
      }
      res.json({ updated: updated.length, rules: updated });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Update a fee rule
  app.patch('/api/contracts/:contractId/rules/:ruleId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId, ruleId } = req.params;
      const userId = req.user?.id;
      const context = req.user?.activeContext;
      const updateData = req.body;

      if (await enforceContractEditLock(req, res, contractId)) return;

      // Get the rule first to verify it exists
      const [rule] = await db
        .select()
        .from(contractRules)
        .where(eq(contractRules.id, ruleId))
        .limit(1);
      
      if (!rule) {
        return res.status(404).json({ error: 'Rule not found' });
      }
      
      // Verify rule belongs to the contract
      if (rule.contractId !== contractId) {
        return res.status(400).json({ error: 'Rule does not belong to this contract' });
      }
      
      // Get the contract to check multi-tenant authorization
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      
      // Multi-tenant authorization check
      const userRole = (await storage.getUser(userId))?.role;
      const isAdmin = userRole === 'admin' || userRole === 'owner';
      if (!isAdmin && context?.companyId && contract.companyId !== context.companyId) {
        return res.status(403).json({ error: 'Access denied: Contract belongs to different organization' });
      }
      
      // Build update object - only include allowed fields
      const allowedFields = [
        'ruleName', 'ruleType', 'baseRate', 'calculation', 'description',
        'productCategories', 'territories', 'volumeTiers', 'seasonalAdjustments',
        'territoryPremiums', 'effectiveDate', 'endDate', 'isActive', 'priority',
        'minimumGuarantee', 'formulaDefinition', 'conditions', 'fieldMappings',
        'clauseCategory', 'channel', 'customerSegments', 'extractionOrder',
        'expiryDate', 'aggregationPeriod',
        'templateCode', 'executionGroup', 'baseMetric', 'fieldConfidence',
        'reviewFlags', 'minimumPrice', 'exceptions',
        'specificityScore', 'sourceSection', 'sourceText', 'confidence',
        'calculationFormula', 'reviewStatus',
        'calcPhase', 'triggerSource', 'aggregationScope',
      ];
      
      const updateObj: any = { updatedAt: new Date() };
      const dateFields = ['effectiveDate', 'expiryDate', 'endDate', 'reviewedAt'];
      for (const field of allowedFields) {
        if (updateData[field] !== undefined) {
          if (dateFields.includes(field) && updateData[field]) {
            updateObj[field] = new Date(updateData[field]);
          } else {
            updateObj[field] = updateData[field];
          }
        }
      }
      
      // Phase taxonomy is server-managed: validate any explicit values and,
      // if `ruleType` is being changed without an explicit `calcPhase`,
      // recompute it from the new ruleType so we never persist a stale or
      // malformed phase tag. Mirrors PUT /api/contract-rules/:ruleId.
      const {
        resolveCalcPhase: _resolvePhase,
        normalizeCalcPhase: _normCp2,
        normalizeTriggerSource: _normTs2,
        normalizeAggregationScope: _normAs2,
      } = await import('@shared/calcPhases.js');
      // Empty string and null are explicitly invalid — never persist a blank
      // taxonomy value. Callers that want a default must omit the field.
      if (updateObj.calcPhase !== undefined) {
        const n = _normCp2(updateObj.calcPhase);
        if (!n) return res.status(400).json({ error: `Invalid calcPhase: ${updateObj.calcPhase}` });
        updateObj.calcPhase = n;
      }
      if (updateObj.triggerSource !== undefined) {
        const n = _normTs2(updateObj.triggerSource);
        if (!n) return res.status(400).json({ error: `Invalid triggerSource: ${updateObj.triggerSource}` });
        updateObj.triggerSource = n;
      }
      if (updateObj.aggregationScope !== undefined) {
        const n = _normAs2(updateObj.aggregationScope);
        if (!n) return res.status(400).json({ error: `Invalid aggregationScope: ${updateObj.aggregationScope}` });
        updateObj.aggregationScope = n;
      }
      if (
        updateObj.ruleType !== undefined
        && updateObj.ruleType !== rule.ruleType
        && updateObj.calcPhase === undefined
      ) {
        updateObj.calcPhase = _resolvePhase({ ruleType: updateObj.ruleType });
      }

      // Verification regression: editing the substance of a verified rule
      // means the human-confirmed extraction no longer matches the saved
      // values, so reviewStatus must drop back to under_review until a
      // reviewer re-verifies. Mirrors PUT /api/contract-rules/:ruleId.
      const editsRuleSubstance = Object.keys(updateObj).some(k =>
        !['updatedAt', 'reviewStatus', 'reviewedBy', 'reviewedAt', 'isActive'].includes(k)
      );
      if (
        editsRuleSubstance
        && (rule as any).reviewStatus === 'verified'
        && updateObj.reviewStatus === undefined
      ) {
        updateObj.reviewStatus = 'under_review';
        updateObj.reviewedBy = null;
        updateObj.reviewedAt = null;
      }

      // Update the rule
      await db
        .update(contractRules)
        .set(updateObj)
        .where(eq(contractRules.id, ruleId));
      
      // Fetch the updated rule
      const [updatedRule] = await db
        .select()
        .from(contractRules)
        .where(eq(contractRules.id, ruleId))
        .limit(1);
      
      try {
        const { revertContractApprovalIfRulesIncomplete } = await import("./services/contractApprovalIntegrity");
        await revertContractApprovalIfRulesIncomplete(contractId, `Rule '${(updatedRule as any)?.ruleName || ruleId}' was edited`);
      } catch (revertErr) {
        console.error("[contractApprovalIntegrity] patch-contract-rules revert failed:", revertErr);
      }
      console.log(`✏️ Rule ${ruleId} updated by user ${userId}`);
      res.json(updatedRule);
    } catch (error: any) {
      console.error('Update rule error:', error);
      res.status(500).json({ error: error.message || 'Failed to update rule' });
    }
  });

  // AI-native field mapping detection for rule table data
  app.post('/api/contracts/:contractId/rules/:ruleId/ai-field-mappings', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { ruleId } = req.params;
      const { columns, sampleRows, ruleName } = req.body;
      
      if (!columns || !Array.isArray(columns) || columns.length === 0) {
        return res.status(400).json({ error: 'columns array is required' });
      }
      
      const sampleData = (sampleRows || []).slice(0, 3).map((row: any) => {
        const sample: Record<string, string> = {};
        columns.forEach((col: string) => {
          if (row[col] !== undefined && row[col] !== null && row[col] !== '') {
            sample[col] = String(row[col]);
          }
        });
        return sample;
      });
      
      const prompt = `You are analyzing a pricing/payment table extracted from a contract. Your job is to determine what calculation role each column plays.

Rule Name: "${ruleName || 'Unknown'}"

Table columns: ${JSON.stringify(columns)}

Sample data (first ${sampleData.length} rows):
${sampleData.map((row: any, i: number) => `Row ${i + 1}: ${JSON.stringify(row)}`).join('\n')}

For each column, determine its calculation role from these options:
- "volumeField": Contains volume ranges, quantities, or thresholds for tier matching (e.g. "0 — 1,000 units", "5,001+", quantity ranges)
- "rateField": Contains the rate, percentage, fee, or price to apply (e.g. "2.0%", "$1.50", "5%")
- "basisField": Contains what the rate is applied against (e.g. "Net Sales", "Gross Revenue", "Total Purchases")
- "minimumField": Contains minimum payment amounts or guarantees
- "descriptionField": Contains labels, tier names, product names, or descriptions (e.g. "Tier 1", "Standard", "Headphones")

Rules:
1. Each column can have at most ONE role
2. Each role can be assigned to at most ONE column
3. Not every column needs a role — only assign roles that clearly fit
4. Look at BOTH the column name AND the sample data values to determine the role
5. A column with values like "Tier 1", "Tier 2" is a descriptionField
6. A column with values like "0 — 1,000 units" is a volumeField
7. A column with values like "2.0%", "5.0%" is a rateField
8. A column with values like "Net Sales", "Gross Sales" is a basisField

Respond with ONLY a JSON object mapping role names to column names. Example:
{"volumeField": "Quarterly Unit Volume", "rateField": "Rebate Percentage", "basisField": "Basis", "descriptionField": "Tier"}`;

      const aiResponse = await groqService.makeRequest(
        [
          { role: 'system', content: 'You are a contract data analysis expert. Respond with ONLY valid JSON, no explanation.' },
          { role: 'user', content: prompt }
        ],
        0.1,
        512
      );
      
      let mappings: Record<string, string> = {};
      try {
        const jsonMatch = aiResponse.match(/\{[\s\S]*\}/);
        if (jsonMatch) {
          mappings = JSON.parse(jsonMatch[0]);
        }
      } catch (parseErr) {
        console.error('[AI-FIELD-MAPPINGS] Failed to parse AI response:', aiResponse);
        const fallback = autoDetectFieldMappingsFallback(columns);
        return res.json({ mappings: fallback || {}, source: 'fallback' });
      }
      
      // Validate: only keep recognized field roles mapped to actual columns
      const validRoles = ['volumeField', 'rateField', 'basisField', 'minimumField', 'descriptionField'];
      const validated: Record<string, string> = {};
      for (const [role, col] of Object.entries(mappings)) {
        if (validRoles.includes(role) && columns.includes(col)) {
          validated[role] = col;
        }
      }
      
      console.log(`🤖 [AI-FIELD-MAPPINGS] Rule "${ruleName}": ${JSON.stringify(validated)}`);
      res.json({ mappings: validated, source: 'ai' });
    } catch (error: any) {
      console.error('[AI-FIELD-MAPPINGS] Error:', error);
      res.status(500).json({ error: 'Failed to detect field mappings' });
    }
  });

