  // Mint a fresh pending_approval version for a contract. Used by the
  // readiness checklist's "Approve & Activate" flow when no draft exists
  // yet (e.g. AI-imported contracts that haven't been hand-edited).
  // Idempotent: if a draft / pending_approval version already exists,
  // returns it as-is.
  app.post('/api/contracts/:id/versions/mint', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const userId = req.user.id;
      const contract = await storage.getContract(contractId);
      if (!contract) return res.status(404).json({ error: 'Contract not found' });

      // Reuse an existing open version instead of stacking new ones.
      const existing = await storage.getContractVersions(contractId);
      const open = (existing || []).find(
        (v: any) => v.approvalState === 'pending_approval' || v.approvalState === 'draft',
      );
      if (open) {
        // Promote a draft to pending_approval so the approve endpoint accepts it.
        if (open.approvalState === 'draft') {
          await db.execute(sql`
            UPDATE contract_versions SET approval_state = 'pending_approval' WHERE id = ${open.id}
          `);
          return res.json({ version: { ...open, approvalState: 'pending_approval' }, reused: true });
        }
        return res.json({ version: open, reused: true });
      }

      const nextNumber = (existing?.[0]?.versionNumber || 0) + 1;
      const created = await storage.createContractVersion({
        contractId,
        versionNumber: nextNumber,
        editorId: userId,
        changeSummary: 'Auto-minted for approval via readiness checklist',
        metadataSnapshot: contract,
        approvalState: 'pending_approval',
      });
      res.json({ version: created, reused: false });
    } catch (error: any) {
      console.error('Mint version error:', error);
      res.status(500).json({ error: error.message || 'Failed to mint version' });
    }
  });

  // Approve or reject a contract version
  app.post('/api/contracts/versions/:versionId/approve', isAuthenticated, async (req: any, res: Response) => {
    try {
      const versionId = req.params.versionId;
      const userId = req.user.id;
      const { status, decisionNotes, adminOverride } = req.body; // status: 'approved' or 'rejected', adminOverride: boolean

      // Validate status
      if (status !== 'approved' && status !== 'rejected') {
        return res.status(400).json({ error: 'Status must be either "approved" or "rejected"' });
      }

      // Get version
      const version = await storage.getContractVersion(versionId);
      if (!version) {
        return res.status(404).json({ error: 'Version not found' });
      }

      // Check if user is an approver (admin or owner only)
      const user = await storage.getUser(userId);
      const canApprove = user?.role === 'admin' || user?.role === 'owner';
      
      if (!canApprove) {
        return res.status(403).json({ error: 'Only admins and owners can approve contracts' });
      }

      // Prevent self-approval unless admin override is enabled
      if (version.editorId === userId) {
        // Allow admin override for admins only
        if (adminOverride && user?.role === 'admin') {
          console.log(`⚠️ Admin override: ${user.username} is force-approving their own changes for version ${versionId}`);
        } else {
          return res.status(403).json({ error: 'You cannot approve your own changes' });
        }
      }

      // Check if version is in pending_approval state
      if (version.approvalState !== 'pending_approval') {
        return res.status(400).json({ error: 'This version is not pending approval' });
      }

      // Integrity gate: a contract can only be APPROVED when every active rule
      // attached to it is also approved. This prevents the silent-failure mode
      // where a half-approved contract still calculates fees but skips the
      // unapproved rules. Rejection bypasses the gate (rejecting a contract
      // doesn't require the rules to be in any particular state).
      if (status === 'approved') {
        const { getRuleApprovalSummary } = await import('./services/contractApprovalIntegrity');
        const summary = await getRuleApprovalSummary(version.contractId);
        if (!summary.isFullyApproved) {
          return res.status(400).json({
            error: summary.total === 0
              ? 'This contract has no active rules to approve. Add and approve at least one rule before approving the contract.'
              : `Contract approval is blocked: ${summary.pending} rule(s) still need sign-off${summary.rejected > 0 ? ` and ${summary.rejected} were rejected` : ''}. ${summary.approved} of ${summary.total} rules are approved.`,
            blocking: {
              total: summary.total,
              approved: summary.approved,
              pending: summary.pending,
              rejected: summary.rejected,
              ruleIds: summary.blockingRuleIds,
            },
          });
        }
      }

      // Create approval record
      const approval = await storage.createContractApproval({
        contractVersionId: versionId,
        approverId: userId,
        status,
        decisionNotes,
      });

      // Promote the contract itself to "active" once a version is approved,
      // so the pipeline strip in the editor advances to the Activate step.
      // Rejection leaves the contract status untouched.
      if (status === 'approved') {
        await db.execute(sql`
          UPDATE contracts
             SET status = 'active', updated_at = NOW()
           WHERE id = ${version.contractId}
        `);
        await db.execute(sql`
          UPDATE contract_versions
             SET approval_state = 'approved'
           WHERE id = ${versionId}
        `);
      } else if (status === 'rejected') {
        await db.execute(sql`
          UPDATE contract_versions
             SET approval_state = 'rejected'
           WHERE id = ${versionId}
        `);
      }

      // Create audit log
      await createAuditLog(req, `contract_${status}`, 'contract_version', versionId, {
        notes: decisionNotes,
        approver: user?.username,
      });

      res.json(approval);
    } catch (error: any) {
      console.error('Approval error:', error);
      res.status(500).json({ error: error.message || 'Failed to process approval' });
    }
  });

  // Get pending approvals for the current user
  app.get('/api/approvals/pending', isAuthenticated, async (req: any, res: Response) => {
    try {
      const userId = req.user.id;

      // Check if user is an approver
      const user = await storage.getUser(userId);
      const canApprove = user?.role === 'admin' || user?.role === 'owner';
      
      if (!canApprove) {
        return res.json({ approvals: [] }); // Return empty array if user can't approve
      }

      // Get pending approvals
      const approvals = await storage.getPendingApprovals(userId);

      res.json({ approvals });
    } catch (error: any) {
      console.error('Get pending approvals error:', error);
      res.status(500).json({ error: error.message || 'Failed to fetch pending approvals' });
    }
  });

  // Calculate royalties for all sales matched to this contract
  app.post('/api/contracts/:id/calculate-matched-royalties', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const { periodStart, periodEnd } = req.body;
      
      // Get contract and check permissions
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }

      const userId = req.user.id;
      const userRole = (await storage.getUser(userId))?.role;
      const canView = userRole === 'admin' || userRole === 'owner' || contract.uploadedBy === userId;
      
      if (!canView) {
        return res.status(403).json({ error: 'Access denied' });
      }

      // Get all sales matched to this contract
      const { dynamicRulesEngine } = await import('./services/dynamicRulesEngine.js');
      const allSales = await storage.getSalesDataByContract(contractId);
      
      // Filter by date range if provided
      let salesToCalculate = allSales;
      if (periodStart || periodEnd) {
        salesToCalculate = allSales.filter(sale => {
          const saleDate = new Date(sale.transactionDate);
          if (periodStart && saleDate < new Date(periodStart)) return false;
          if (periodEnd && saleDate > new Date(periodEnd)) return false;
          return true;
        });
      }

      // 🚫 Rebate eligibility pre-filter: strip non-eligible transaction types
      const NON_ELIGIBLE_TXN_TYPES = new Set(['return', 'sample', 'warranty', 'demo', 'promo']);
      const beforeFilterCount = salesToCalculate.length;
      salesToCalculate = salesToCalculate.filter(sale => {
        const cf = (sale.customFields as Record<string, any>) || {};
        const txnType = String(cf.transaction_type || cf.transactionType || cf.TransactionType || '').toLowerCase().trim();
        return !NON_ELIGIBLE_TXN_TYPES.has(txnType);
      });
      const filteredOut = beforeFilterCount - salesToCalculate.length;
      if (filteredOut > 0) {
        console.log(`[CALC] Rebate eligibility filter excluded ${filteredOut} non-eligible sales (return/sample/warranty/demo/promo)`);
      }

      if (salesToCalculate.length === 0) {
        return res.json({ 
          success: true,
          totalRoyalty: 0, 
          salesCount: 0,
          breakdown: [],
          message: 'No sales data matched to this contract' 
        });
      }

      const salesItems = salesToCalculate.map(sale => ({
        id: sale.id,
        productName: sale.productName || 'Unknown',
        category: sale.category || '',
        territory: sale.territory || 'Primary Territory',
        quantity: parseFloat(sale.quantity || '0'),
        transactionDate: new Date(sale.transactionDate),
        grossAmount: parseFloat(sale.grossAmount || '0'),
        netAmount: parseFloat(sale.netAmount || sale.grossAmount || '0'),
        customFields: (sale.customFields as Record<string, string>) || undefined,
      }));

      const result = await dynamicRulesEngine.calculateRoyalty(contractId, salesItems);

      const breakdown = result.breakdown.map(item => ({
        saleId: item.saleId,
        productName: item.productName,
        category: item.category,
        territory: item.territory,
        quantity: item.quantity,
        royaltyAmount: item.calculatedRoyalty,
        ruleApplied: item.ruleApplied,
        explanation: item.explanation,
        tierRate: item.tierRate,
        seasonalMultiplier: item.seasonalMultiplier,
        territoryMultiplier: item.territoryMultiplier
      }));

      res.json({
        success: true,
        contractId,
        contractName: contract.originalName,
        calculatedRoyalty: result.totalRoyalty,
        totalRoyalty: result.finalRoyalty,
        minimumGuarantee: result.minimumGuarantee,
        finalRoyalty: result.finalRoyalty,
        salesCount: salesToCalculate.length,
        periodStart,
        periodEnd,
        breakdown,
        rulesApplied: result.rulesApplied,
        currency: 'USD'
      });

    } catch (error) {
      console.error('Fee calculation error:', error);
      res.status(500).json({ error: 'Failed to calculate fees' });
    }
  });

