  app.patch('/api/royalty-calculations/:calcId/status', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { calcId } = req.params;
      const { status, rejectionReason } = req.body;
      const userId = req.user.id;

      if (!['approved', 'rejected', 'pending_approval'].includes(status)) {
        return res.status(400).json({ error: 'Status must be approved, rejected, or pending_approval' });
      }

      const { contractCalculations } = await import('@shared/schema');
      const { eq } = await import('drizzle-orm');

      const [calc] = await db.select().from(contractCalculations).where(eq(contractCalculations.id, calcId));
      if (!calc) {
        return res.status(404).json({ error: 'Calculation not found' });
      }

      const updateData: any = { status, updatedAt: new Date() };
      if (status === 'approved') {
        updateData.approvedBy = userId;
        updateData.approvedAt = new Date();
        updateData.rejectedBy = null;
        updateData.rejectedAt = null;
        updateData.rejectionReason = null;
      } else if (status === 'rejected') {
        updateData.rejectedBy = userId;
        updateData.rejectedAt = new Date();
        updateData.rejectionReason = rejectionReason || '';
        updateData.approvedBy = null;
        updateData.approvedAt = null;
      } else {
        updateData.approvedBy = null;
        updateData.approvedAt = null;
        updateData.rejectedBy = null;
        updateData.rejectedAt = null;
        updateData.rejectionReason = null;
      }

      const [updated] = await db.update(contractCalculations)
        .set(updateData)
        .where(eq(contractCalculations.id, calcId))
        .returning();

      await createAuditLog(req, `calculation_${status}`, 'royalty_calculation', calcId, {
        totalRoyalty: calc.totalRoyalty,
        rejectionReason: rejectionReason || undefined
      });

      res.json(updated);
    } catch (error: any) {
      console.error('Update calculation status error:', error);
      res.status(500).json({ error: error.message || 'Failed to update calculation status' });
    }
  });

