  app.post('/api/admin/leads/create-account', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (req.user?.role !== 'admin' && req.user?.role !== 'owner') {
        return res.status(403).json({ error: 'Access denied' });
      }
      const { leadId, leadType, companyName, userEmail, tempPassword, firstName, lastName, role: assignedRole, sourceCompanyId } = req.body;
      if (!leadId || !leadType || !companyName || !userEmail || !tempPassword) {
        return res.status(400).json({ error: 'All fields are required: leadId, leadType, companyName, userEmail, tempPassword' });
      }
      const validRoles = ['admin', 'editor', 'viewer', 'accountant'];
      const userRole = validRoles.includes(assignedRole) ? assignedRole : 'admin';

      const userName = userEmail.toLowerCase();
      const existingUser = await storage.getUserByUsername(userName);
      if (existingUser) {
        return res.status(400).json({ error: `An account with email "${userEmail}" already exists.` });
      }
      const existingEmail = await storage.getUserByEmail(userEmail);
      if (existingEmail) {
        return res.status(400).json({ error: `An account with email "${userEmail}" already exists.` });
      }

      const adminUserId = req.user.id;

      const company = await storage.createCompany({
        companyName,
        status: 'A',
        contactPerson: `${firstName || ''} ${lastName || ''}`.trim() || userName,
        contactEmail: userEmail,
        createdBy: adminUserId,
        lastUpdatedBy: adminUserId,
      });

      if (sourceCompanyId) {
        try {
          const copyResult = await copyCompanySchemaData(sourceCompanyId, company.id);
          console.log(`✅ Copied master data from source company to ${companyName}:`, JSON.stringify(copyResult));
        } catch (copyErr: any) {
          console.error(`⚠️ Failed to copy master data: ${copyErr.message}`);
        }
      }

      const { hashPassword } = await import('./auth.js');
      const hashedPassword = await hashPassword(tempPassword);
      const newUser = await storage.createUser({
        username: userName,
        password: hashedPassword,
        email: userEmail,
        firstName: firstName || null,
        lastName: lastName || null,
        role: userRole,
        isActive: true,
      });

      const orgRole = await storage.createUserOrganizationRole({
        userId: newUser.id,
        companyId: company.id,
        role: userRole,
        status: 'A',
        createdBy: adminUserId,
        lastUpdatedBy: adminUserId,
      });

      await storage.setUserActiveContext(newUser.id, orgRole.id);

      const { renderEmail } = await import('./email-templates.js');
      const { sendZohoEmail } = await import('./zoho-mail.js');
      const loginUrl = getAppUrl(req);
      const vars = {
        name: firstName || userName,
        email: userEmail,
        company: companyName,
        loginUrl,
        tempPassword,
        year: new Date().getFullYear().toString(),
      };
      const { subject, html } = await renderEmail('workspace_ready', vars);
      await sendZohoEmail({ to: userEmail, subject, html });

      const statusNote = `Account created on ${new Date().toLocaleDateString()}. Company: ${companyName}. Login: ${userName}. Welcome email sent.`;
      if (leadType === 'early_access') {
        await storage.updateEarlyAccessSignupStatus(leadId, 'converted', statusNote);
      } else if (leadType === 'demo_request') {
        await storage.updateDemoRequestStatus(leadId, 'converted', statusNote);
      }

      const roleLabel = userRole === 'admin' ? 'Company Admin' : userRole === 'editor' ? 'Editor' : userRole === 'viewer' ? 'Viewer' : userRole === 'accountant' ? 'Accountant' : 'Company Admin';
      await storage.appendLeadActivity(leadId, leadType, { action: 'account_created', details: `Company "${companyName}" created. User account created with login: ${userName}. Role: ${roleLabel}.`, by: req.user?.username || 'admin' });
      await storage.appendLeadActivity(leadId, leadType, { action: 'email_sent', details: `Workspace ready email sent to ${userEmail}`, emailSubject: subject, by: req.user?.username || 'admin' });
      await storage.appendLeadActivity(leadId, leadType, { action: 'status_changed', details: 'Status changed to "converted"', by: req.user?.username || 'admin' });

      console.log(`✅ Account created: Company="${companyName}", Login="${userName}", Email="${userEmail}"`);
      res.json({
        success: true,
        message: `Account created successfully. Welcome email sent to ${userEmail}.`,
        companyId: company.id,
        userId: newUser.id,
      });
    } catch (error: any) {
      console.error('Create account error:', error);
      res.status(500).json({ error: error.message || 'Failed to create account' });
    }
  });

  app.post('/api/admin/leads/reset-password', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (req.user?.role !== 'admin' && req.user?.role !== 'owner') {
        return res.status(403).json({ error: 'Access denied' });
      }
      const { leadId, leadType, email, newPassword } = req.body;
      if (!email || !newPassword || newPassword.length < 6) {
        return res.status(400).json({ error: 'Email and a password (min 6 chars) are required' });
      }

      const user = await storage.getUserByEmail(email);
      if (!user) {
        return res.status(404).json({ error: `No user account found for email "${email}". The account may not have been created yet.` });
      }

      const { hashPassword } = await import('./auth.js');
      const hashedPassword = await hashPassword(newPassword);
      await storage.resetUserPassword(user.id, hashedPassword);

      const { renderEmail } = await import('./email-templates.js');
      const { sendZohoEmail } = await import('./zoho-mail.js');
      const loginUrl = getAppUrl(req);
      const vars = {
        name: user.firstName || user.username,
        email,
        company: '',
        loginUrl,
        tempPassword: newPassword,
        year: new Date().getFullYear().toString(),
      };
      const { subject, html } = await renderEmail('workspace_ready', vars);
      await sendZohoEmail({ to: email, subject, html });

      if (leadId && leadType) {
        await storage.appendLeadActivity(leadId, leadType, { action: 'password_reset', details: `Password reset for ${email}. New credentials email sent.`, emailSubject: subject, by: req.user?.username || 'admin' });
      }

      console.log(`🔑 Password reset for ${email} by ${req.user?.username}`);
      res.json({ success: true, message: `Password reset successfully. New credentials email sent to ${email}.` });
    } catch (error: any) {
      console.error('Reset password error:', error);
      res.status(500).json({ error: error.message || 'Failed to reset password' });
    }
  });

  app.post('/api/admin/sql-console', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (req.user?.role !== 'admin' && req.user?.role !== 'owner') {
        return res.status(403).json({ error: 'Access denied. Admin only.' });
      }
      const { query } = req.body;
      if (!query || typeof query !== 'string') {
        return res.status(400).json({ error: 'Query is required' });
      }
      const trimmed = query.trim().toLowerCase();
      const forbidden = ['drop database', 'drop schema', 'truncate', 'alter system'];
      for (const f of forbidden) {
        if (trimmed.includes(f)) {
          return res.status(403).json({ error: `Forbidden operation: ${f.toUpperCase()}` });
        }
      }
      const startTime = Date.now();
      const result = await db.execute(sql.raw(query));
      const elapsed = Date.now() - startTime;
      const rows = result.rows || [];
      const columns = rows.length > 0 ? Object.keys(rows[0]) : [];
      const isWrite = /^(insert|update|delete|create|alter|drop)/i.test(trimmed);
      res.json({
        columns,
        rows: rows.slice(0, 1000),
        rowCount: rows.length,
        truncated: rows.length > 1000,
        elapsed,
        isWrite,
        message: isWrite ? `${result.rowCount ?? 0} row(s) affected` : `${rows.length} row(s) returned`,
      });
    } catch (error: any) {
      res.status(400).json({ error: error.message });
    }
  });

  app.get('/api/admin/sql-console/tables', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (req.user?.role !== 'admin' && req.user?.role !== 'owner') {
        return res.status(403).json({ error: 'Access denied' });
      }
      const tables = await db.execute(sql`
        SELECT table_name, 
               (SELECT COUNT(*) FROM information_schema.columns c WHERE c.table_name = t.table_name AND c.table_schema = 'public') as column_count
        FROM information_schema.tables t 
        WHERE table_schema = 'public' AND table_type = 'BASE TABLE'
        ORDER BY table_name
      `);
      const tableDetails = [];
      for (const t of tables.rows as any[]) {
        const cols = await db.execute(sql.raw(`SELECT column_name, data_type, is_nullable FROM information_schema.columns WHERE table_name = '${t.table_name}' AND table_schema = 'public' ORDER BY ordinal_position`));
        const countResult = await db.execute(sql.raw(`SELECT COUNT(*)::int as cnt FROM "${t.table_name}"`));
        tableDetails.push({
          name: t.table_name,
          columnCount: parseInt(t.column_count),
          rowCount: (countResult.rows[0] as any)?.cnt || 0,
          columns: cols.rows,
        });
      }
      res.json(tableDetails);
    } catch (error: any) {
      res.status(500).json({ error: error.message });
    }
  });

