  // ======================
  // PENDING TERM MAPPINGS API (ERP-Aware Extraction)
  // ======================

  // Get company-level term mappings (Company Mapping Library)
  app.get('/api/company-mappings', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { status, contractId, companyId: filterCompanyId } = req.query;
      const userCompanyId = req.user.activeContext?.companyId || req.user.companyId;
      const userRole = (await storage.getUser(req.user?.id))?.role;
      const isAdmin = userRole === 'admin' || userRole === 'owner' || req.user?.isSystemAdmin;
      
      let companyId = userCompanyId;
      
      if (filterCompanyId) {
        if (!isAdmin) {
          return res.status(403).json({ error: 'Access denied: Only admins can filter by company' });
        }
        companyId = filterCompanyId as string;
      }
      
      if (contractId) {
        const contract = await storage.getContract(contractId as string);
        if (!contract) {
          return res.status(404).json({ error: 'Contract not found' });
        }
        if (contract.companyId) {
          if (!isAdmin && companyId && contract.companyId !== companyId) {
            return res.status(403).json({ error: 'Access denied: Contract belongs to different organization' });
          }
          companyId = contract.companyId;
        }
      }
      
      if (!companyId) {
        const userOrgRoles = await db.execute(sql`
          SELECT DISTINCT company_id FROM user_organization_roles 
          WHERE user_id = ${req.user.id} AND (status = 'active' OR status = 'A')
        `);
        if (userOrgRoles.rows.length === 1) {
          companyId = (userOrgRoles.rows[0] as any).company_id;
        }
      }
      
      if (!companyId) {
        return res.status(400).json({ error: 'Company context required. Please select an organization from the location switcher.' });
      }
      
      const mappings = await storage.getPendingTermMappingsByCompany(companyId, status as string | undefined, contractId as string | undefined);
      
      // Merge contract rule terms into the mapping library
      // For 'pending' status: show rules with review_status != 'rejected' and != 'auto_confirmed'
      // For 'confirmed' status: show rules with review_status = 'confirmed' (manually confirmed only)
      // Decompose volume_tiers into individual term entries for per-row mapping
      let ruleTerms: any = { rows: [] };
      const contractFilter = contractId ? sql`AND rr.contract_id = ${contractId as string}` : sql``;
      const ruleColumns = sql`rr.id, rr.contract_id, c.company_id,
            rr.rule_name as original_term, rr.description as original_value,
            rr.source_text, rr.source_section, rr.source_page,
            rr.rule_type as erp_field_name, rr.confidence,
            rr.review_status as status, rr.reviewed_by as confirmed_by,
            rr.reviewed_at as confirmed_at, c.display_name as contract_name,
            rr.extraction_order, rr.created_at, rr.volume_tiers, rr.base_rate,
            rr.formula_definition`;
      if (status === 'pending') {
        ruleTerms = await db.execute(sql`
          SELECT ${ruleColumns}
          FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id
          WHERE c.company_id = ${companyId}
            AND (rr.review_status IS NULL OR rr.review_status = 'auto_confirmed' OR rr.review_status NOT IN ('rejected', 'confirmed'))
            ${contractFilter}
          ORDER BY rr.extraction_order ASC, rr.created_at DESC
        `);
      } else if (status === 'confirmed') {
        ruleTerms = await db.execute(sql`
          SELECT ${ruleColumns}
          FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id
          WHERE c.company_id = ${companyId}
            AND rr.review_status = 'confirmed'
            ${contractFilter}
          ORDER BY rr.extraction_order ASC, rr.created_at DESC
        `);
      } else if (!status) {
        ruleTerms = await db.execute(sql`
          SELECT ${ruleColumns}
          FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id
          WHERE c.company_id = ${companyId}
            AND (rr.review_status IS NULL OR rr.review_status != 'rejected')
            ${contractFilter}
          ORDER BY rr.extraction_order ASC, rr.created_at DESC
        `);
      }
      
      const ruleIds = (ruleTerms.rows as any[]).map((r: any) => r.id);
      let confirmedRuleMappingsMap: Record<string, any> = {};
      if (ruleIds.length > 0) {
        const confirmedRuleMappings = await db.execute(sql`
          SELECT * FROM pending_term_mappings
          WHERE company_id = ${companyId}
            AND status = 'confirmed'
            AND mapping_method LIKE 'contract_rule_%'
        `);
        for (const cm of (confirmedRuleMappings.rows as any[])) {
          confirmedRuleMappingsMap[cm.mapping_method] = cm;
        }
      }
      
      const confirmedRuleMappingIds = new Set(Object.values(confirmedRuleMappingsMap).map((m: any) => m.id));
      
      const ruleTermMappings: any[] = [];
      for (const row of (ruleTerms.rows as any[])) {
        const ruleMappingKey = `contract_rule_${row.id}`;
        const confirmedMapping = confirmedRuleMappingsMap[ruleMappingKey];
        
        ruleTermMappings.push({
          id: confirmedMapping ? confirmedMapping.id : `rule-${row.id}`,
          contractId: row.contract_id,
          companyId: row.company_id,
          originalTerm: row.original_term,
          originalValue: row.original_value || null,
          sourceText: row.source_text || null,
          sourceSection: row.source_section || null,
          sourcePage: row.source_page || null,
          erpFieldName: confirmedMapping?.erp_field_name || row.erp_field_name || 'Contract Rule',
          erpEntityName: confirmedMapping?.erp_entity_name || null,
          erpFieldId: confirmedMapping?.erp_field_id || null,
          erpEntityId: confirmedMapping?.erp_entity_id || null,
          erpRecordId: confirmedMapping?.erp_record_id || null,
          erpRecordValue: confirmedMapping?.erp_record_value || null,
          erpRecordTable: confirmedMapping?.erp_record_table || null,
          confidence: parseFloat(row.confidence) || 0.9,
          status: row.status === 'auto_confirmed' ? 'confirmed' : row.status,
          confirmedBy: confirmedMapping?.confirmed_by || row.confirmed_by,
          confirmedAt: confirmedMapping?.confirmed_at || row.confirmed_at,
          contractName: row.contract_name,
          termType: 'contract_rule',
          ruleId: row.id,
        });
        
        let tiers = row.volume_tiers;
        
        if ((!Array.isArray(tiers) || tiers.length === 0) && row.formula_definition) {
          const formulaDef = typeof row.formula_definition === 'string' 
            ? JSON.parse(row.formula_definition) : row.formula_definition;
          const tableRows = formulaDef?.tableData?.rows || formulaDef?.calculation?.tableData?.rows;
          if (Array.isArray(tableRows) && tableRows.length > 0) {
            tiers = tableRows;
          }
        }
        
        if (Array.isArray(tiers) && tiers.length > 0) {
          tiers.forEach((tier: any, index: number) => {
            const tierNum = index + 1;
            const tierFields = Object.entries(tier).filter(([key]) => key !== 'size');
            const tierValues = tierFields.map(([key, val]) => `${key}: ${val}`).join(', ');
            const tierMappingKey = `contract_rule_tier_${row.id}_${index}`;
            const confirmedTierMapping = confirmedRuleMappingsMap[tierMappingKey];
            
            ruleTermMappings.push({
              id: confirmedTierMapping ? confirmedTierMapping.id : `rule-tier-${row.id}-${index}`,
              contractId: row.contract_id,
              companyId: row.company_id,
              originalTerm: `Tier ${tierNum} (${row.original_term})`,
              originalValue: tierValues || null,
              sourceText: row.source_text || null,
              sourceSection: row.source_section || null,
              sourcePage: row.source_page || null,
              erpFieldName: confirmedTierMapping?.erp_field_name || 'Tier Detail',
              erpEntityName: confirmedTierMapping?.erp_entity_name || null,
              erpFieldId: confirmedTierMapping?.erp_field_id || null,
              erpEntityId: confirmedTierMapping?.erp_entity_id || null,
              erpRecordId: confirmedTierMapping?.erp_record_id || null,
              erpRecordValue: confirmedTierMapping?.erp_record_value || null,
              erpRecordTable: confirmedTierMapping?.erp_record_table || null,
              confidence: parseFloat(row.confidence) || 0.9,
              status: confirmedTierMapping ? 'confirmed' : (row.status === 'auto_confirmed' ? 'confirmed' : row.status),
              confirmedBy: confirmedTierMapping?.confirmed_by || row.confirmed_by,
              confirmedAt: confirmedTierMapping?.confirmed_at || row.confirmed_at,
              contractName: row.contract_name,
              termType: 'contract_rule_tier',
              ruleId: row.id,
              tierData: tier,
              tierIndex: index,
            });
          });
        }
      }
      
      const fieldMappings = mappings
        .filter((m: any) => !confirmedRuleMappingIds.has(m.id))
        .map((m: any) => ({ ...m, termType: 'field_mapping' }));
      const allMappings = [...fieldMappings, ...ruleTermMappings].sort((a: any, b: any) => {
        const getPriority = (m: any) => {
          const entity = (m.erpEntityName || '').toLowerCase();
          const field = (m.erpFieldName || '').toLowerCase();
          if (entity === 'partner_master' && field.includes('partner_name')) return 0;
          if (entity === 'partner_master' || field.includes('vendor') || field.includes('party')) return 1;
          if (m.termType === 'field_mapping' && (m.confidence || 0) >= 0.8) return 2;
          if (m.termType === 'contract_rule') return 3;
          if (m.termType === 'contract_rule_tier') return 4;
          if (m.termType === 'field_mapping') return 5;
          return 6;
        };
        const pa = getPriority(a);
        const pb = getPriority(b);
        if (pa !== pb) return pa - pb;
        return (b.confidence || 0) - (a.confidence || 0);
      });
      
      console.log(`📋 [COMPANY MAPPINGS] Found ${fieldMappings.length} field mappings + ${ruleTermMappings.length} rule terms (incl. tiers) for company ${companyId} (storage returned ${mappings.length} raw)`);
      res.set('Cache-Control', 'no-cache, no-store, must-revalidate');
      res.json({ mappings: allMappings, companyId });
    } catch (error) {
      console.error('❌ [COMPANY MAPPINGS] Get error:', error);
      res.status(500).json({ error: 'Failed to retrieve company mappings' });
    }
  });

