  // Confirm a single pending mapping
  app.post('/api/pending-mappings/:id/confirm', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { id } = req.params;
      const { modifiedValue, modifiedFieldId, modifiedEntityName, modifiedFieldName, erpRecordId, erpRecordValue, erpRecordTable } = req.body;
      const userId = req.user.id;
      
      let actualId = id;
      
      // Handle virtual IDs for contract rule/tier items
      if (id.startsWith('rule-tier-') || id.startsWith('rule-')) {
        const ruleId = id.startsWith('rule-tier-') 
          ? id.replace('rule-tier-', '').replace(/-\d+$/, '')
          : id.replace('rule-', '');
        
        // Fetch the original rule data
        const ruleResult = await db.execute(sql`
          SELECT rr.*, c.company_id, c.display_name as contract_name
          FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id
          WHERE rr.id = ${ruleId}
        `);
        
        if (ruleResult.rows.length === 0) {
          return res.status(404).json({ error: 'Rule not found' });
        }
        
        const rule = ruleResult.rows[0] as any;
        let originalTerm = rule.rule_name;
        let originalValue = rule.description || null;
        let mappingMethod = 'contract_rule_mapping';
        
        // For tier items, use tier-specific data
        if (id.startsWith('rule-tier-')) {
          const tierIndex = parseInt(id.split('-').pop() || '0');
          const tiers = rule.volume_tiers;
          if (Array.isArray(tiers) && tiers[tierIndex]) {
            const tier = tiers[tierIndex];
            const tierFields = Object.entries(tier).filter(([key]) => key !== 'size');
            originalTerm = `Tier ${tierIndex + 1} (${rule.rule_name})`;
            originalValue = tierFields.map(([key, val]) => `${key}: ${val}`).join(', ');
            mappingMethod = `contract_rule_tier_${ruleId}_${tierIndex}`;
          }
        } else {
          mappingMethod = `contract_rule_${ruleId}`;
        }
        
        // Check for existing mapping to prevent duplicates
        const existingCheck = await db.execute(sql`
          SELECT id FROM pending_term_mappings 
          WHERE mapping_method = ${mappingMethod} AND contract_id = ${rule.contract_id}
          LIMIT 1
        `);
        
        if (existingCheck.rows.length > 0) {
          actualId = (existingCheck.rows[0] as any).id;
          console.log(`📋 [PENDING MAPPINGS] Reusing existing mapping ${actualId} for virtual ${id}`);
        } else {
          const newMapping = await storage.createPendingTermMapping({
            contractId: rule.contract_id,
            companyId: rule.company_id,
            originalTerm,
            originalValue,
            sourceText: rule.source_text || null,
            sourceSection: rule.source_section || null,
            sourcePage: rule.source_page || null,
            erpFieldName: modifiedFieldId || rule.rule_type || 'Contract Rule',
            erpEntityName: null,
            confidence: parseFloat(rule.confidence) || 0.9,
            status: 'pending',
            mappingMethod,
          });
          actualId = newMapping.id;
          console.log(`📋 [PENDING MAPPINGS] Created real mapping ${actualId} from virtual ${id}`);
        }
        
        // Also update the rule's review_status to 'confirmed'
        await db.execute(sql`
          UPDATE contract_rules SET review_status = 'confirmed', reviewed_by = ${userId}, reviewed_at = NOW()
          WHERE id = ${ruleId}
        `);
      }
      
      const mapping = await storage.confirmPendingTermMapping(actualId, userId, modifiedValue, modifiedFieldId, erpRecordId, erpRecordValue, erpRecordTable, modifiedEntityName, modifiedFieldName);
      console.log(`✅ [PENDING MAPPINGS] Confirmed mapping: ${actualId}`);
      
      // Auto-generate ERP mapping rule from confirmed mapping
      try {
        const { generateRuleFromMapping } = await import('./services/erpRuleGenerationService');
        const generatedRule = await generateRuleFromMapping(actualId, userId);
        if (generatedRule) {
          console.log(`✅ [AUTO-RULE] Generated rule: ${generatedRule.ruleName}`);
        }
      } catch (ruleError) {
        console.log(`ℹ️ [AUTO-RULE] Rule generation skipped:`, ruleError);
      }
      
      res.json(mapping);
    } catch (error) {
      console.error('❌ [PENDING MAPPINGS] Confirm error:', error);
      res.status(500).json({ error: 'Failed to confirm mapping' });
    }
  });

  // Bulk confirm multiple mappings
  app.post('/api/pending-mappings/bulk-confirm', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { mappingIds } = req.body;
      const userId = req.user.id;
      
      if (!mappingIds || !Array.isArray(mappingIds) || mappingIds.length === 0) {
        return res.status(400).json({ error: 'mappingIds array is required' });
      }
      
      // Separate real IDs from virtual IDs
      const realIds: string[] = [];
      const virtualIds: string[] = [];
      for (const id of mappingIds) {
        if (id.startsWith('rule-tier-') || id.startsWith('rule-')) {
          virtualIds.push(id);
        } else {
          realIds.push(id);
        }
      }
      
      // Create real entries for virtual IDs first (with deduplication)
      for (const virtualId of virtualIds) {
        const ruleId = virtualId.startsWith('rule-tier-') 
          ? virtualId.replace('rule-tier-', '').replace(/-\d+$/, '')
          : virtualId.replace('rule-', '');
        
        const ruleResult = await db.execute(sql`
          SELECT rr.*, c.company_id FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id WHERE rr.id = ${ruleId}
        `);
        
        if (ruleResult.rows.length === 0) continue;
        const rule = ruleResult.rows[0] as any;
        let originalTerm = rule.rule_name;
        let originalValue = rule.description || null;
        let mappingMethod = virtualId.startsWith('rule-tier-') 
          ? `contract_rule_tier_${ruleId}_${virtualId.split('-').pop()}`
          : `contract_rule_${ruleId}`;
        
        if (virtualId.startsWith('rule-tier-')) {
          const tierIndex = parseInt(virtualId.split('-').pop() || '0');
          const tiers = rule.volume_tiers;
          if (Array.isArray(tiers) && tiers[tierIndex]) {
            const tier = tiers[tierIndex];
            const tierFields = Object.entries(tier).filter(([key]) => key !== 'size');
            originalTerm = `Tier ${tierIndex + 1} (${rule.rule_name})`;
            originalValue = tierFields.map(([key, val]) => `${key}: ${val}`).join(', ');
          }
        }
        
        // Check for existing mapping to prevent duplicates
        const existingCheck = await db.execute(sql`
          SELECT id FROM pending_term_mappings 
          WHERE mapping_method = ${mappingMethod} AND contract_id = ${rule.contract_id}
          LIMIT 1
        `);
        
        if (existingCheck.rows.length > 0) {
          realIds.push((existingCheck.rows[0] as any).id);
        } else {
          const newMapping = await storage.createPendingTermMapping({
            contractId: rule.contract_id,
            companyId: rule.company_id,
            originalTerm,
            originalValue,
            sourceText: rule.source_text || null,
            sourceSection: rule.source_section || null,
            sourcePage: rule.source_page || null,
            erpFieldName: rule.rule_type || 'Contract Rule',
            erpEntityName: null,
            confidence: parseFloat(rule.confidence) || 0.9,
            status: 'pending',
            mappingMethod,
          });
          realIds.push(newMapping.id);
        }
        
        // Update rule review_status to 'confirmed'
        await db.execute(sql`
          UPDATE contract_rules SET review_status = 'confirmed', reviewed_by = ${userId}, reviewed_at = NOW()
          WHERE id = ${ruleId}
        `);
        console.log(`📋 [BULK] Resolved mapping for virtual ${virtualId}`);
      }
      
      const mappings = await storage.bulkConfirmPendingTermMappings(realIds, userId);
      console.log(`✅ [PENDING MAPPINGS] Bulk confirmed ${mappings.length} mappings`);
      
      // Auto-generate ERP mapping rules from confirmed mappings
      try {
        const { generateRulesFromMappings } = await import('./services/erpRuleGenerationService');
        const generatedRules = await generateRulesFromMappings(realIds, userId);
        console.log(`✅ [AUTO-RULE] Generated ${generatedRules.length} rules from bulk confirm`);
      } catch (ruleError) {
        console.log(`ℹ️ [AUTO-RULE] Bulk rule generation skipped:`, ruleError);
      }
      
      // Trigger blueprint materialization for affected contracts
      try {
        const contractIds = [...new Set(mappings.map(m => m.contractId))];
        const { blueprintMaterializerService } = await import('./services/blueprintMaterializerService');
        for (const contractId of contractIds) {
          const result = await blueprintMaterializerService.onMappingsConfirmed(contractId);
          console.log(`📐 [BLUEPRINT] Materialized ${result.blueprintsCreated} blueprints for contract ${contractId}`);
        }
      } catch (materializeError) {
        console.log(`ℹ️ [BLUEPRINT] Materialization skipped:`, materializeError);
      }
      
      res.json({ mappings, count: mappings.length });
    } catch (error) {
      console.error('❌ [PENDING MAPPINGS] Bulk confirm error:', error);
      res.status(500).json({ error: 'Failed to bulk confirm mappings' });
    }
  });

