  // Formula health assessment for a contract's rules
  app.get('/api/contracts/:id/formula-health', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const rules = await storage.getRoyaltyRulesByContract(contractId);
      const { buildFormulaDefinition } = await import('@shared/formulaDefinitionBuilder');
      
      const assessments = rules.map(rule => {
        const fd = rule.formulaDefinition as any;
        let status: 'healthy' | 'warning' | 'error' = 'error';
        let message = 'No formula found';
        let formulaType = 'none';
        
        if (fd) {
          if (fd.formula && fd.formula.type) {
            status = 'healthy';
            formulaType = fd.formula.type;
            message = 'Ready for calculation';
          } else if (fd.tableData && fd.tableData.rows?.length > 0) {
            const fm = rule.fieldMappings as any;
            if (fm && (fm.rateField || fm.volumeField)) {
              status = 'healthy';
              formulaType = 'table-derived';
              message = 'Table data with field mappings - formula will be built on-the-fly';
            } else {
              const rows = fd.tableData.rows || [];
              const hasNumericRates = rows.some((row: any) => {
                const vals = Object.values(row);
                return vals.some((v: any) => typeof v === 'number' && v > 0 && v < 100);
              });
              if (hasNumericRates) {
                status = 'warning';
                formulaType = 'table-unmapped';
                message = 'Table data present but field mappings needed';
              } else {
                status = 'warning';
                formulaType = 'data-only';
                message = 'Reference data only - not used for calculations';
              }
            }
          } else if (fd.baseRate && typeof fd.baseRate === 'number') {
            status = 'healthy';
            formulaType = 'ai-percentage';
            message = `AI-extracted rate: ${fd.baseRate}`;
          } else if (fd.fixedAmount && typeof fd.fixedAmount === 'number') {
            status = 'healthy';
            formulaType = 'ai-fixed';
            message = `AI-extracted fixed amount: ${fd.fixedAmount}`;
          } else if (fd.tiers && Array.isArray(fd.tiers) && fd.tiers.length > 0) {
            status = 'healthy';
            formulaType = 'ai-tiered';
            message = `AI-extracted ${fd.tiers.length} tiers`;
          } else if (fd.minimumGuarantee) {
            status = 'healthy';
            formulaType = 'minimum-guarantee';
            message = `Minimum guarantee: ${fd.minimumGuarantee}`;
          } else {
            status = 'warning';
            formulaType = 'incomplete';
            message = 'Formula definition exists but cannot be evaluated';
          }
        } else if (rule.baseRate) {
          status = 'healthy';
          formulaType = 'legacy-rate';
          message = `Legacy base rate: ${rule.baseRate}`;
        } else if (rule.volumeTiers && Array.isArray(rule.volumeTiers) && (rule.volumeTiers as any[]).length > 0) {
          status = 'healthy';
          formulaType = 'legacy-tiered';
          message = `Legacy ${(rule.volumeTiers as any[]).length} tiers`;
        }

        return {
          ruleId: rule.id,
          ruleName: rule.ruleName,
          ruleType: rule.ruleType,
          isActive: rule.isActive,
          status,
          formulaType,
          message,
        };
      });
      
      const healthy = assessments.filter(a => a.status === 'healthy').length;
      const warnings = assessments.filter(a => a.status === 'warning').length;
      const errors = assessments.filter(a => a.status === 'error').length;
      
      res.json({
        contractId,
        totalRules: assessments.length,
        healthy,
        warnings, 
        errors,
        overallStatus: errors > 0 ? 'error' : warnings > 0 ? 'warning' : 'healthy',
        assessments,
      });
    } catch (error: any) {
      console.error('[FORMULA-HEALTH] Error:', error);
      res.status(500).json({ error: error.message || 'Failed to assess formula health' });
    }
  });

  // Test/simulate a single rule with sample data
  app.post('/api/rules/:id/test', isAuthenticated, async (req: any, res: Response) => {
    try {
      const ruleId = req.params.id;
      const { grossAmount = 1000, netAmount, quantity = 1, category = 'General', territory = 'Default', containerSize = '' } = req.body;
      
      const { contractRules } = await import('@shared/schema');
      const { eq } = await import('drizzle-orm');
      const ruleResults = await db.select().from(contractRules).where(eq(contractRules.id, ruleId));
      const rule = ruleResults[0];
      if (!rule) {
        return res.status(404).json({ error: 'Rule not found' });
      }
      
      const { evaluateFormulaDefinition } = await import('./services/universalFormulaEvaluator');
      const { buildFormulaDefinition } = await import('@shared/formulaDefinitionBuilder');
      
      let formula: any = null;
      const fd = rule.formulaDefinition as any;
      
      if (fd) {
        if (fd.formula && fd.formula.type) {
          formula = fd;
        } else if (fd.tableData && fd.tableData.rows?.length > 0) {
          const fm = rule.fieldMappings as any;
          if (fm) {
            try {
              formula = buildFormulaDefinition({
                tableData: fd.tableData,
                fieldMappings: { volume: fm.volumeField, rate: fm.rateField, minimum: fm.minimumField, description: fm.descriptionField },
                ruleName: rule.ruleName || 'Test Rule',
                minimumGuarantee: rule.minimumGuarantee ? parseFloat(rule.minimumGuarantee) : undefined,
              });
            } catch (e) {}
          }
        } else if (fd.baseRate && typeof fd.baseRate === 'number') {
          const basisField = fd.calculationBasis?.toLowerCase().includes('net') ? 'netAmount' : 'grossAmount';
          const fdType = (fd.type || '').toLowerCase();
          const isPercentage = fdType === 'percentage' || rule.ruleType === 'percentage' || !fd.type ||
            fdType.includes('rebate') || fdType.includes('rate');
          if (isPercentage) {
            formula = { version: '1.0', name: rule.ruleName, formula: { type: 'multiply', operands: [{ type: 'reference', field: basisField }, { type: 'literal', value: fd.baseRate }] } };
          }
        } else if (fd.fixedAmount && typeof fd.fixedAmount === 'number') {
          formula = { version: '1.0', name: rule.ruleName, formula: { type: 'multiply', operands: [{ type: 'reference', field: 'quantity' }, { type: 'literal', value: fd.fixedAmount }] } };
        } else if (fd.tiers && Array.isArray(fd.tiers) && fd.tiers.length > 0) {
          const firstTier = fd.tiers[0];
          const rate = firstTier.rate || 0;
          formula = { version: '1.0', name: rule.ruleName, formula: { type: 'multiply', operands: [{ type: 'reference', field: 'grossAmount' }, { type: 'literal', value: rate }] } };
        }
      } else if (rule.baseRate) {
        const rate = parseFloat(rule.baseRate);
        formula = { version: '1.0', name: rule.ruleName, formula: { type: 'multiply', operands: [{ type: 'reference', field: 'grossAmount' }, { type: 'literal', value: rate }] } };
      }
      
      if (!formula) {
        return res.json({
          success: false,
          error: 'Could not build a testable formula from this rule',
          ruleName: rule.ruleName,
        });
      }
      
      const effectiveNetAmount = netAmount != null ? netAmount : grossAmount;
      const context = {
        grossAmount, netAmount: effectiveNetAmount, quantity, productName: 'Test Product',
        category, territory, containerSize, transactionDate: new Date(),
        unitPrice: grossAmount / (quantity || 1), units: quantity,
        fields: { grossAmount, netAmount: effectiveNetAmount, productName: 'Test Product', category, territory, containerSize, transactionDate: new Date().toISOString(), quantity, units: quantity }
      };
      
      const result = evaluateFormulaDefinition(formula, context);
      
      res.json({
        success: result.success,
        ruleName: rule.ruleName,
        ruleType: rule.ruleType,
        inputData: { grossAmount, netAmount: effectiveNetAmount, quantity, category, territory },
        calculatedFee: result.success ? result.value : 0,
        auditTrail: result.auditTrail || [],
        error: result.success ? null : (result.error || 'Evaluation failed'),
      });
    } catch (error: any) {
      console.error('[RULE-TEST] Error:', error);
      res.status(500).json({ error: error.message || 'Failed to test rule' });
    }
  });

