  // Update a pending mapping
  app.patch('/api/pending-mappings/:id', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { id } = req.params;
      const updates = req.body;
      
      // Always null out erpEntityId and erpFieldId to avoid foreign key constraints
      // since we're using LicenseIQ schema fields which are stored by name only
      const safeUpdates = {
        ...updates,
        erpEntityId: null,
        erpFieldId: null,
      };
      
      let actualId = id;
      
      // Handle virtual IDs for contract rule/tier items - create real mapping first
      if (id.startsWith('rule-tier-') || id.startsWith('rule-')) {
        const ruleId = id.startsWith('rule-tier-') 
          ? id.replace('rule-tier-', '').replace(/-\d+$/, '')
          : id.replace('rule-', '');
        
        const ruleResult = await db.execute(sql`
          SELECT rr.*, c.company_id FROM contract_rules rr
          JOIN contracts c ON rr.contract_id = c.id WHERE rr.id = ${ruleId}
        `);
        
        if (ruleResult.rows.length === 0) {
          return res.status(404).json({ error: 'Rule not found' });
        }
        
        const rule = ruleResult.rows[0] as any;
        let originalTerm = rule.rule_name;
        let originalValue = rule.description || null;
        let mappingMethod = id.startsWith('rule-tier-') 
          ? `contract_rule_tier_${ruleId}_${id.split('-').pop()}`
          : `contract_rule_${ruleId}`;
        
        if (id.startsWith('rule-tier-')) {
          const tierIndex = parseInt(id.split('-').pop() || '0');
          const tiers = rule.volume_tiers;
          if (Array.isArray(tiers) && tiers[tierIndex]) {
            const tier = tiers[tierIndex];
            const tierFields = Object.entries(tier).filter(([key]) => key !== 'size');
            originalTerm = `Tier ${tierIndex + 1} (${rule.rule_name})`;
            originalValue = tierFields.map(([key, val]) => `${key}: ${val}`).join(', ');
          }
        }
        
        // Check for existing mapping to prevent duplicates
        const existingCheck = await db.execute(sql`
          SELECT id FROM pending_term_mappings 
          WHERE mapping_method = ${mappingMethod} AND contract_id = ${rule.contract_id}
          LIMIT 1
        `);
        
        if (existingCheck.rows.length > 0) {
          actualId = (existingCheck.rows[0] as any).id;
        } else {
          const newMapping = await storage.createPendingTermMapping({
            contractId: rule.contract_id,
            companyId: rule.company_id,
            originalTerm,
            originalValue,
            sourceText: rule.source_text || null,
            sourceSection: rule.source_section || null,
            sourcePage: rule.source_page || null,
            erpFieldName: safeUpdates.erpFieldName || rule.rule_type || 'Contract Rule',
            erpEntityName: safeUpdates.erpEntityName || null,
            confidence: parseFloat(rule.confidence) || 0.9,
            status: 'pending',
            mappingMethod,
          });
          actualId = newMapping.id;
        }
        console.log(`📋 [PENDING MAPPINGS] Resolved mapping ${actualId} from virtual ${id}`);
      }
      
      const mapping = await storage.updatePendingTermMapping(actualId, safeUpdates);
      console.log(`✏️ [PENDING MAPPINGS] Updated mapping: ${actualId}`);
      res.json(mapping);
    } catch (error) {
      console.error('❌ [PENDING MAPPINGS] Update error:', error);
      res.status(500).json({ error: 'Failed to update mapping' });
    }
  });

