  app.delete('/api/company-mappings/bulk', isAuthenticated, async (req: any, res: Response) => {
    try {
      const user = req.user as any;
      let companyId = user.activeContext?.companyId || user.activeCompanyId || user.companyId;
      const status = req.query.status as string;
      const contractId = req.query.contractId as string | undefined;

      if (contractId) {
        const contract = await storage.getContract(contractId);
        if (contract?.companyId) {
          companyId = contract.companyId;
        }
      }

      if (!companyId) {
        const userOrgRoles = await db.execute(sql`
          SELECT DISTINCT company_id FROM user_organization_roles 
          WHERE user_id = ${user.id} AND (status = 'active' OR status = 'A')
        `);
        if (userOrgRoles.rows.length === 1) {
          companyId = (userOrgRoles.rows[0] as any).company_id;
        }
      }

      if (!companyId) {
        return res.status(400).json({ error: 'No company context' });
      }
      if (!status || !['pending', 'confirmed'].includes(status)) {
        return res.status(400).json({ error: 'Invalid status parameter. Must be "pending" or "confirmed".' });
      }

      let deletedMappings = 0;
      let deletedRules = 0;

      const mappingConditions = [
        eq(pendingTermMappings.companyId, companyId),
        eq(pendingTermMappings.status, status)
      ];
      if (contractId) {
        mappingConditions.push(eq(pendingTermMappings.contractId, contractId));
      }
      const mappingResult = await db.delete(pendingTermMappings)
        .where(and(...mappingConditions));
      deletedMappings = (mappingResult as any)?.rowCount || 0;

      if (status === 'pending') {
        const ruleFilter = contractId 
          ? sql`AND rr.contract_id = ${contractId}`
          : sql``;
        const ruleResult = await db.execute(sql`
          UPDATE contract_rules rr
          SET review_status = 'rejected', reviewed_at = NOW()
          FROM contracts c
          WHERE rr.contract_id = c.id
            AND c.company_id = ${companyId}
            AND (rr.review_status IS NULL OR rr.review_status = 'auto_confirmed' OR rr.review_status NOT IN ('rejected', 'confirmed'))
            ${ruleFilter}
        `);
        deletedRules = (ruleResult as any)?.rowCount || 0;
      } else if (status === 'confirmed') {
        const ruleFilter = contractId 
          ? sql`AND rr.contract_id = ${contractId}`
          : sql``;
        const ruleResult = await db.execute(sql`
          UPDATE contract_rules rr
          SET review_status = 'rejected', reviewed_at = NOW()
          FROM contracts c
          WHERE rr.contract_id = c.id
            AND c.company_id = ${companyId}
            AND rr.review_status = 'confirmed'
            ${ruleFilter}
        `);
        deletedRules = (ruleResult as any)?.rowCount || 0;
      }

      console.log(`🗑️ [COMPANY MAPPINGS] Deleted all ${status} for company ${companyId}: ${deletedMappings} mappings, ${deletedRules} rules`);
      res.json({ success: true, deletedMappings, deletedRules });
    } catch (error) {
      console.error('❌ [COMPANY MAPPINGS] Bulk delete error:', error);
      res.status(500).json({ error: 'Failed to delete mappings' });
    }
  });

  // Lightweight value-suggestion endpoint used by the Rule Editor side panel.
  // Given a free-text value (e.g. "Headphones") and a dimension (product /
  // territory / channel / partner / company), it returns the top master-data
  // candidate(s) with confidence and method using the existing fuzzy matcher.
  app.post('/api/mapping/value-suggest', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { value, dimension, companyId: companyIdInput } = req.body || {};
      if (!value || typeof value !== 'string' || value.trim().length === 0) {
        return res.status(400).json({ error: 'value (string) is required' });
      }
      const dim = String(dimension || '').toLowerCase();
      const dimensionToEntity: Record<string, string> = {
        product: 'products',
        products: 'products',
        sku: 'products',
        product_category: 'product_hierarchy',
        category: 'product_hierarchy',
        product_hierarchy: 'product_hierarchy',
        hierarchy: 'product_hierarchy',
        territory: 'territory_master',
        territories: 'territory_master',
        region: 'territory_master',
        country: 'territory_master',
        channel: 'sales_channels',
        channels: 'sales_channels',
        sales_channel: 'sales_channels',
        partner: 'partner_master',
        partners: 'partner_master',
        company: 'company_master',
        customer: 'customers',
        customers: 'customers',
      };
      const entityTechnicalName = dimensionToEntity[dim];
      if (!entityTechnicalName) {
        return res.status(400).json({ error: `Unsupported dimension: ${dim}. Use product, territory, channel, partner, company, or customer.` });
      }

      const user = req.user as any;
      const companyId = companyIdInput || user?.activeContext?.companyId || user?.activeCompanyId || user?.companyId || null;

      const { getEntityRecords, findBestMatch } = await import('./services/valueLinkingService');
      const cleanValue = value.trim();

      const records = await getEntityRecords(entityTechnicalName, companyId);
      const top = findBestMatch(cleanValue, records, entityTechnicalName);

      // Build a small set of alternatives (best 3 by score, excluding the top)
      const scored: Array<{ recordId: string; recordValue: string; field: string; confidence: number; method: string; table: string }> = [];
      if (top) {
        scored.push({
          recordId: top.recordId,
          recordValue: top.recordValue,
          field: top.matchedField,
          confidence: Number(top.confidence.toFixed(3)),
          method: top.matchMethod,
          table: top.recordTable,
        });
      }
      // Brute-force alternatives: re-run findBestMatch over slices to gather variety.
      const seen = new Set<string>(scored.map((s) => s.recordId));
      for (let i = 0; i < records.length && scored.length < 4; i += 25) {
        const slice = records.slice(i, i + 25).filter((r) => !seen.has(r.id));
        const m = findBestMatch(cleanValue, slice, entityTechnicalName);
        if (m && !seen.has(m.recordId) && m.confidence >= 0.4) {
          seen.add(m.recordId);
          scored.push({
            recordId: m.recordId,
            recordValue: m.recordValue,
            field: m.matchedField,
            confidence: Number(m.confidence.toFixed(3)),
            method: m.matchMethod,
            table: m.recordTable,
          });
        }
      }

      const status: 'verified' | 'suggested' | 'unmapped' =
        !top || top.confidence < 0.5 ? 'unmapped' : top.confidence >= 0.95 ? 'verified' : 'suggested';

      res.json({
        value: cleanValue,
        dimension: dim,
        entityTechnicalName,
        status,
        topConfidence: top ? Number(top.confidence.toFixed(3)) : 0,
        candidatesScanned: records.length,
        suggestions: scored,
      });
    } catch (error: any) {
      console.error('[VALUE-SUGGEST] Error:', error);
      res.status(500).json({ error: error?.message || 'Failed to suggest mapping' });
    }
  });

  // ----- Per-value mapping persistence (used by the Rule Editor side panel) -----
  // We store the user's accepted mapping inside contract_qualifiers.notes as a
  // JSON marker prefixed with "[liQ-link]" so we don't need a schema change.
  // Format: [liQ-link]{"recordId":"...","recordValue":"...","confidence":0.92,"method":"fuzzy","at":"..."}<rest>
  const LINK_MARKER = "[liQ-link]";

  function buildLinkNote(payload: {
    recordId: string;
    recordValue: string;
    confidence: number;
    method: string;
  }, existingNotes?: string | null) {
    const json = JSON.stringify({
      recordId: payload.recordId,
      recordValue: payload.recordValue,
      confidence: payload.confidence,
      method: payload.method,
      at: new Date().toISOString(),
    });
    const stripped = (existingNotes || "").replace(/\[liQ-link\]\{[^\n]*\}/g, "").trim();
    return stripped ? `${stripped}\n${LINK_MARKER}${json}` : `${LINK_MARKER}${json}`;
  }

  function clearLinkNote(existingNotes?: string | null) {
    return (existingNotes || "").replace(/\[liQ-link\]\{[^\n]*\}/g, "").trim();
  }

  function parseLinkNote(notes?: string | null): null | {
    recordId: string;
    recordValue: string;
    confidence: number;
    method: string;
    at?: string;
  } {
    if (!notes) return null;
    const m = notes.match(/\[liQ-link\](\{[^\n]*\})/);
    if (!m) return null;
    try { return JSON.parse(m[1]); } catch { return null; }
  }

  function dimensionToQualifierFields(dimension: string): string[] {
    const dim = dimension.toLowerCase();
    if (dim === "product" || dim === "products" || dim === "product_category" || dim === "category" || dim === "sku") {
      return ["product", "product_category", "sku"];
    }
    if (dim === "territory" || dim === "territories" || dim === "region" || dim === "country") {
      return ["territory", "region", "country"];
    }
    if (dim === "channel" || dim === "channels" || dim === "sales_channel") {
      return ["channel", "sales_channel"];
    }
    return [dim];
  }

  app.post('/api/mapping/accept', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId, dimension, value, recordId, recordValue, confidence, method } = req.body || {};
      if (!contractId || !dimension || !value) {
        return res.status(400).json({ error: 'contractId, dimension, value are required' });
      }
      const fields = dimensionToQualifierFields(String(dimension));
      const cleanValue = String(value).trim().replace(/^!/, "");
      const { contractQualifiers } = await import("@shared/schema");
      const { eq, and, inArray } = await import("drizzle-orm");
      const rows = await db.select().from(contractQualifiers)
        .where(and(
          eq(contractQualifiers.contractId, contractId),
          inArray(contractQualifiers.qualifierField, fields),
          eq(contractQualifiers.qualifierValue, cleanValue),
        ));
      const isClear = !recordId;
      let updatedCount = 0;
      for (const row of rows) {
        const newNotes = isClear
          ? clearLinkNote(row.notes)
          : buildLinkNote({
              recordId,
              recordValue: recordValue || cleanValue,
              confidence: typeof confidence === 'number' ? confidence : 0,
              method: method || 'manual',
            }, row.notes);
        await db.update(contractQualifiers)
          .set({ notes: newNotes || null })
          .where(eq(contractQualifiers.qualifierId, row.qualifierId));
        updatedCount++;
      }
      res.json({ success: true, updated: updatedCount, qualifiersFound: rows.length });
    } catch (error: any) {
      console.error('[MAPPING-ACCEPT] Error:', error);
      res.status(500).json({ error: error?.message || 'Failed to persist mapping' });
    }
  });

  app.get('/api/mapping/accepted', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = String(req.query.contractId || '');
      if (!contractId) return res.status(400).json({ error: 'contractId is required' });
      const { contractQualifiers } = await import("@shared/schema");
      const { eq } = await import("drizzle-orm");
      const rows = await db.select().from(contractQualifiers)
        .where(eq(contractQualifiers.contractId, contractId));
      const links: Array<{ dimension: string; value: string; recordId: string; recordValue: string; confidence: number; method: string }> = [];
      const dedupe = new Set<string>();
      for (const row of rows) {
        const link = parseLinkNote(row.notes);
        if (!link) continue;
        const dim = (row.qualifierField === 'territory' || row.qualifierField === 'region' || row.qualifierField === 'country')
          ? 'territory'
          : (row.qualifierField === 'channel' || row.qualifierField === 'sales_channel')
          ? 'channel'
          : 'product';
        const key = `${dim}::${(row.qualifierValue || '').toLowerCase()}`;
        if (dedupe.has(key)) continue;
        dedupe.add(key);
        links.push({
          dimension: dim,
          value: row.qualifierValue || '',
          recordId: link.recordId,
          recordValue: link.recordValue,
          confidence: link.confidence,
          method: link.method,
        });
      }
      res.json({ links });
    } catch (error: any) {
      console.error('[MAPPING-ACCEPTED] Error:', error);
      res.status(500).json({ error: error?.message || 'Failed to load mappings' });
    }
  });

  // Helper used by the review-status gate below.
  async function findUnmappedRefsForRule(ruleId: string): Promise<string[]> {
    const { contractQualifiers, contractRules } = await import("@shared/schema");
    const { eq, and, inArray } = await import("drizzle-orm");
    const [rule] = await db.select().from(contractRules).where(eq(contractRules.id, ruleId)).limit(1);
    if (!rule) return [];
    const toList = (v: any): string[] => {
      const raw = Array.isArray(v) ? v : (typeof v === "string" ? v.split(",") : []);
      return raw
        .map((x: any) => String(x ?? "").trim().replace(/^!/, ""))
        .filter((x: string) => x && x !== "*" && x.toLowerCase() !== "general");
    };
    const products = toList(rule.productCategories);
    const territories = toList(rule.territories);
    if (products.length === 0 && territories.length === 0) return [];
    const allValues = [
      ...products.map(v => ({ v, dim: 'product' as const })),
      ...territories.map(v => ({ v, dim: 'territory' as const })),
    ];
    // Pull qualifiers for THIS contract and check link markers.
    const qrows = await db.select().from(contractQualifiers)
      .where(eq(contractQualifiers.contractId, rule.contractId as string));
    const linkedSet = new Set<string>();
    for (const r of qrows) {
      const link = parseLinkNote(r.notes);
      if (!link) continue;
      const dim = (r.qualifierField === 'territory' || r.qualifierField === 'region' || r.qualifierField === 'country')
        ? 'territory'
        : (r.qualifierField === 'channel' || r.qualifierField === 'sales_channel')
        ? 'channel'
        : 'product';
      linkedSet.add(`${dim}::${(r.qualifierValue || '').toLowerCase()}`);
    }
    const unmapped: string[] = [];
    for (const { v, dim } of allValues) {
      if (!linkedSet.has(`${dim}::${v.toLowerCase()}`)) {
        unmapped.push(`${dim}: ${v}`);
      }
    }
    return unmapped;
  }

