  // Re-extract table terms and category names from existing rules and add to pending mappings
  // This allows users to refresh AI Mapping Suggestions without re-uploading the contract
  app.post('/api/contracts/:contractId/extract-table-terms', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId } = req.params;
      
      const contract = await storage.getContract(contractId);
      const contractCompanyId = contract?.companyId || null;
      
      // Get all rules for this contract
      const rules = await storage.getRoyaltyRulesByContract(contractId);
      console.log(`📊 [TABLE TERMS] Extracting from ${rules.length} rules for contract: ${contractId}`);
      
      let tableTermsAdded = 0;
      let categoryTermsAdded = 0;
      const errors: string[] = [];
      
      // 1. Extract table column headers and cell values
      for (const rule of rules) {
        const formulaDef = rule.formulaDefinition as any;
        const tableDataSource = formulaDef?.tableData;
        
        if (tableDataSource) {
          const result = await extractTableDataTerms(
            contractId,
            tableDataSource,
            rule.ruleName || 'Unknown Rule',
            undefined,
            contractCompanyId
          );
          tableTermsAdded += result.termsAdded;
          errors.push(...result.errors);
        }
      }
      
      // 2. Extract category/tier names from rule names (universal approach)
      const categoryResult = await extractRuleCategoryTerms(
        contractId,
        rules.map(r => ({ ruleName: r.ruleName || '', ruleType: r.ruleType || '', description: r.description || '' })),
        undefined,
        contractCompanyId
      );
      categoryTermsAdded = categoryResult.termsAdded;
      errors.push(...categoryResult.errors);
      
      const totalTermsAdded = tableTermsAdded + categoryTermsAdded;
      console.log(`✅ [TABLE TERMS] Added ${tableTermsAdded} table terms + ${categoryTermsAdded} category terms = ${totalTermsAdded} total`);
      
      res.json({
        success: true,
        termsAdded: totalTermsAdded,
        tableTermsAdded,
        categoryTermsAdded,
        rulesProcessed: rules.length,
        errors: errors.length > 0 ? errors : undefined
      });
    } catch (error) {
      console.error('❌ [TABLE TERMS] Extraction error:', error);
      res.status(500).json({ error: 'Failed to extract table terms' });
    }
  });

  app.post('/api/contracts/:contractId/extract-erp-entities', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { contractId } = req.params;
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      
      const extractedText = contract.rawText || contract.extractedText || '';
      if (!extractedText) {
        return res.status(400).json({ error: 'No extracted text available for this contract' });
      }
      
      console.log(`🔄 [ERP RETRY] Re-running ERP entity extraction for contract ${contractId}`);
      
      const defaultErpSystemId = '03c4a661-b078-4e6c-bde2-3d32dda784c2';
      const erpResult = await extractWithErpMapping(
        extractedText, contractId, defaultErpSystemId, undefined,
        { autoConfirmHighConfidence: true, confidenceThreshold: 0.85, requireConfirmation: true }
      );
      
      console.log(`✅ [ERP RETRY] Completed: ${erpResult?.termsAdded || 0} terms added`);
      
      res.json({
        success: true,
        termsAdded: erpResult?.termsAdded || 0,
        message: 'ERP entity extraction completed successfully'
      });
    } catch (error: any) {
      console.error('❌ [ERP RETRY] Extraction error:', error);
      res.status(500).json({ error: 'Failed to extract ERP entities', details: error.message });
    }
  });

