  // Get fields for a LicenseIQ entity
  app.get('/api/licenseiq-fields', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { entityId, includeErpMapping } = req.query;
      if (!entityId) {
        return res.status(400).json({ error: 'Entity ID is required' });
      }
      const fields = await storage.getLicenseiqFieldsByEntity(entityId as string);
      
      // Optionally enrich with ERP equivalents
      if (includeErpMapping === 'true') {
        const enrichedFields = await Promise.all(fields.map(async (field) => {
          // Look up ERP mapping for this field
          const mappingResult = await db.execute(sql`
            SELECT 
              ef.field_name as erp_field_name,
              ee.name as erp_entity_name,
              es.name as erp_system_name
            FROM erp_licenseiq_field_mappings m
            JOIN erp_fields ef ON m.erp_field_id = ef.id
            JOIN erp_entities ee ON m.erp_entity_id = ee.id
            JOIN erp_systems es ON m.erp_system_id = es.id
            WHERE m.licenseiq_field_id = ${field.id}
            AND m.is_active = true
            LIMIT 1
          `);
          
          const erpMapping = mappingResult.rows[0] as { erp_field_name: string; erp_entity_name: string; erp_system_name: string } | undefined;
          
          return {
            ...field,
            erpEquivalent: erpMapping ? {
              fieldName: erpMapping.erp_field_name,
              entityName: erpMapping.erp_entity_name,
              systemName: erpMapping.erp_system_name
            } : null
          };
        }));
        return res.json({ fields: enrichedFields });
      }
      
      res.json({ fields });
    } catch (error) {
      console.error('❌ [LICENSEIQ FIELDS] Get error:', error);
      res.status(500).json({ error: 'Failed to retrieve LicenseIQ fields' });
    }
  });

