  // Helper to check if a table has multi-tenant columns
  const hasMultiTenantColumns = async (tableName: string): Promise<{ hasCompany: boolean; hasBU: boolean; hasLocation: boolean }> => {
    const columns = await getValidColumns(tableName);
    return {
      hasCompany: columns.has('company_id'),
      hasBU: columns.has('business_unit_id'),
      hasLocation: columns.has('location_id')
    };
  };

  // Get data from an entity's actual database table with multi-tenant filtering, pagination, sorting, and column filters
  app.get('/api/entity-data/:tableName', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName } = req.params;
      const { 
        page = 1, 
        pageSize = 25, 
        company_id, 
        business_unit_id, 
        location_id,
        sortColumn = 'created_at',
        sortDirection = 'desc'
      } = req.query;

      if (!await isValidEntityTable(tableName)) {
        return res.status(400).json({ error: `Table '${tableName}' is not accessible or not defined in schema catalog` });
      }

      // Check if table supports multi-tenant filtering
      const tenantCols = await hasMultiTenantColumns(tableName);
      const validColumns = await getValidColumns(tableName);
      
      // Enforce company context: non-admin users must use their own context company
      const userCompanyId = req.user.activeContext?.companyId;
      const userRole = (await storage.getUser(req.user?.id))?.role;
      const isAdminUser = userRole === 'admin' || userRole === 'owner' || req.user?.isSystemAdmin;
      let effectiveCompanyId = company_id;
      if (tenantCols.hasCompany) {
        if (!isAdminUser && company_id && company_id !== userCompanyId) {
          return res.status(403).json({ error: 'Access denied: Cannot access data from another organization' });
        }
        if (!isAdminUser && !userCompanyId) {
          return res.status(403).json({ error: 'Access denied: No active company context' });
        }
        if (!effectiveCompanyId && userCompanyId && !isAdminUser) {
          effectiveCompanyId = userCompanyId;
        }
      }
      
      // Build WHERE clause for multi-tenant filtering and column filters
      const whereClauses: string[] = [];
      const queryParams: any[] = [];
      let paramIndex = 1;
      
      // Multi-tenant filters. For tables where company_id is nullable
      // (lookup / reference tables like partner_types, customer_segments),
      // also include rows with company_id IS NULL — those are system-default
      // entries that are visible to every tenant.
      if (effectiveCompanyId && tenantCols.hasCompany) {
        const nullableCheck = await pool.query(
          `SELECT is_nullable FROM information_schema.columns
            WHERE table_schema = 'public' AND table_name = $1 AND column_name = 'company_id'`,
          [tableName]
        );
        const companyIdIsNullable = nullableCheck.rows[0]?.is_nullable === 'YES';
        if (companyIdIsNullable) {
          whereClauses.push(`("company_id" = $${paramIndex} OR "company_id" IS NULL)`);
        } else {
          whereClauses.push(`"company_id" = $${paramIndex}`);
        }
        queryParams.push(effectiveCompanyId);
        paramIndex++;
      }
      if (business_unit_id && tenantCols.hasBU) {
        whereClauses.push(`"business_unit_id" = $${paramIndex}`);
        queryParams.push(business_unit_id);
        paramIndex++;
      }
      if (location_id && tenantCols.hasLocation) {
        whereClauses.push(`"location_id" = $${paramIndex}`);
        queryParams.push(location_id);
        paramIndex++;
      }
      
      // Advanced filters with operators and AND/OR logic
      const { advancedFilters, filterLogic } = req.query;
      const filterClauses: string[] = [];
      
      if (advancedFilters) {
        try {
          const filters = JSON.parse(advancedFilters as string);
          for (const filter of filters) {
            if (!validColumns.has(filter.column)) continue;
            const col = `"${filter.column}"`;
            
            switch (filter.operator) {
              case 'equals':
                filterClauses.push(`CAST(${col} AS TEXT) = $${paramIndex}`);
                queryParams.push(filter.value);
                paramIndex++;
                break;
              case 'contains':
                filterClauses.push(`CAST(${col} AS TEXT) ILIKE $${paramIndex}`);
                queryParams.push(`%${filter.value}%`);
                paramIndex++;
                break;
              case 'starts_with':
                filterClauses.push(`CAST(${col} AS TEXT) ILIKE $${paramIndex}`);
                queryParams.push(`${filter.value}%`);
                paramIndex++;
                break;
              case 'ends_with':
                filterClauses.push(`CAST(${col} AS TEXT) ILIKE $${paramIndex}`);
                queryParams.push(`%${filter.value}`);
                paramIndex++;
                break;
              case 'gt': {
                const numVal = parseFloat(filter.value);
                if (!isNaN(numVal)) {
                  filterClauses.push(`${col} > $${paramIndex}`);
                  queryParams.push(numVal);
                  paramIndex++;
                }
                break;
              }
              case 'gte': {
                const numVal = parseFloat(filter.value);
                if (!isNaN(numVal)) {
                  filterClauses.push(`${col} >= $${paramIndex}`);
                  queryParams.push(numVal);
                  paramIndex++;
                }
                break;
              }
              case 'lt': {
                const numVal = parseFloat(filter.value);
                if (!isNaN(numVal)) {
                  filterClauses.push(`${col} < $${paramIndex}`);
                  queryParams.push(numVal);
                  paramIndex++;
                }
                break;
              }
              case 'lte': {
                const numVal = parseFloat(filter.value);
                if (!isNaN(numVal)) {
                  filterClauses.push(`${col} <= $${paramIndex}`);
                  queryParams.push(numVal);
                  paramIndex++;
                }
                break;
              }
              case 'between': {
                const numVal1 = parseFloat(filter.value);
                const numVal2 = parseFloat(filter.value2);
                if (!isNaN(numVal1) && !isNaN(numVal2)) {
                  filterClauses.push(`${col} BETWEEN $${paramIndex} AND $${paramIndex + 1}`);
                  queryParams.push(numVal1);
                  queryParams.push(numVal2);
                  paramIndex += 2;
                }
                break;
              }
              case 'is_null':
                filterClauses.push(`${col} IS NULL`);
                break;
              case 'not_null':
                filterClauses.push(`${col} IS NOT NULL`);
                break;
            }
          }
        } catch (e) {
          console.error('Failed to parse advanced filters:', e);
        }
        
        // Combine filter clauses with AND or OR
        if (filterClauses.length > 0) {
          const logic = (filterLogic as string)?.toLowerCase() === 'or' ? ' OR ' : ' AND ';
          whereClauses.push(`(${filterClauses.join(logic)})`);
        }
      } else {
        // Simple column filters (filter_columnName=value) - legacy support
        for (const [key, value] of Object.entries(req.query)) {
          if (key.startsWith('filter_') && value) {
            const columnName = key.replace('filter_', '');
            if (validColumns.has(columnName)) {
              whereClauses.push(`CAST("${columnName}" AS TEXT) ILIKE $${paramIndex}`);
              queryParams.push(`%${value}%`);
              paramIndex++;
            }
          }
        }
      }
      
      const whereClause = whereClauses.length > 0 ? `WHERE ${whereClauses.join(' AND ')}` : '';
      
      // Validate and sanitize sort column - use first valid column as fallback instead of hardcoded 'id'
      const validColumnsArray = Array.from(validColumns);
      const defaultSortColumn = validColumnsArray.includes('created_at') ? 'created_at' : (validColumnsArray.includes('id') ? 'id' : validColumnsArray[0] || 'id');
      const safeSortColumn = validColumns.has(sortColumn as string) ? sortColumn : defaultSortColumn;
      const safeSortDirection = (sortDirection as string)?.toLowerCase() === 'asc' ? 'ASC' : 'DESC';
      
      // Calculate pagination
      const pageNum = Math.max(1, parseInt(page as string) || 1);
      const pageSizeNum = Math.min(100, Math.max(1, parseInt(pageSize as string) || 25));
      const offset = (pageNum - 1) * pageSizeNum;
      
      // Add pagination params
      queryParams.push(pageSizeNum);
      queryParams.push(offset);
      
      const result = await pool.query(
        `SELECT * FROM "${tableName}" ${whereClause} ORDER BY "${safeSortColumn}" ${safeSortDirection} NULLS LAST LIMIT $${paramIndex} OFFSET $${paramIndex + 1}`,
        queryParams
      );
      
      // Count query with same filters
      const countParams = queryParams.slice(0, -2); // Remove limit/offset
      const countResult = await pool.query(
        `SELECT COUNT(*) as total FROM "${tableName}" ${whereClause}`,
        countParams
      );
      
      const total = parseInt(countResult.rows[0].total);
      const totalPages = Math.ceil(total / pageSizeNum);
      
      res.json({ 
        records: result.rows, 
        total,
        page: pageNum,
        pageSize: pageSizeNum,
        totalPages,
        filters: { company_id, business_unit_id, location_id },
        tenantColumns: tenantCols
      });
    } catch (error) {
      console.error('❌ [ENTITY DATA] Get error:', error);
      res.status(500).json({ error: 'Failed to retrieve data' });
    }
  });

  // Get columns/schema for an entity's table
  app.get('/api/entity-data/:tableName/columns', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName } = req.params;

      if (!await isValidEntityTable(tableName)) {
        return res.status(400).json({ error: `Table '${tableName}' is not accessible or not defined in schema catalog` });
      }

      const result = await pool.query(`
        SELECT column_name, data_type, is_nullable, column_default 
        FROM information_schema.columns 
        WHERE table_name = $1 AND table_schema = 'public'
        ORDER BY ordinal_position
      `, [tableName]);
      
      res.json({ columns: result.rows });
    } catch (error) {
      console.error('❌ [ENTITY DATA] Get columns error:', error);
      res.status(500).json({ error: 'Failed to retrieve columns' });
    }
  });

  // Generate next code for an entity table
  app.get('/api/entity-data/:tableName/next-code', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName } = req.params;
      if (!await isValidEntityTable(tableName)) {
        return res.status(400).json({ error: `Table '${tableName}' is not accessible` });
      }

      // Find the code column for this table
      const colResult = await pool.query(`
        SELECT column_name FROM information_schema.columns 
        WHERE table_name = $1 AND table_schema = 'public' 
        AND (column_name LIKE '%_code' OR column_name = 'code' OR (column_name LIKE '%_id' AND column_name NOT IN ('id', 'company_id', 'business_unit_id', 'location_id', 'created_by', 'updated_by')))
        ORDER BY ordinal_position LIMIT 1
      `, [tableName]);

      if (colResult.rows.length === 0) {
        return res.json({ code: null, codeColumn: null });
      }

      const codeColumn = colResult.rows[0].column_name;

      const skipAutoGenColumns: Record<string, string[]> = {
        product_packaging_matrix: ['package_code'],
      };
      if (skipAutoGenColumns[tableName]?.includes(codeColumn)) {
        return res.json({ code: null, codeColumn: null });
      }
      
      // Build prefix from table name (e.g., company_master -> COM, partner_master -> PRTN, products -> PROD)
      const prefixMap: Record<string, string> = {
        company_master: "COM", partner_master: "PRTN", products: "PROD",
        customers: "CUST", sales_transactions: "STX", territory_master: "TERR",
        sales_channels: "CH", product_classifications: "CLS", product_hierarchy: "PH",
        product_territory_matrix: "PTM", product_channel_matrix: "PCM",
        product_packaging_matrix: "PPM", product_bom: "BOM",
        product_attributes: "ATTR", partner_contract_associations: "PCA",
      };
      const prefix = prefixMap[tableName] || tableName.substring(0, 3).toUpperCase();

      // Find max existing sequential number across ALL records (not just top 20)
      const maxResult = await pool.query(`
        SELECT "${codeColumn}" FROM "${tableName}" 
        WHERE "${codeColumn}" IS NOT NULL AND "${codeColumn}" LIKE $1
        ORDER BY "${codeColumn}" DESC LIMIT 100
      `, [`${prefix}-%`]);

      let nextNum = 1;
      if (maxResult.rows.length > 0) {
        for (const row of maxResult.rows) {
          const val = row[codeColumn] || '';
          const match = val.match(/(\d+)$/);
          if (match) {
            const num = parseInt(match[1], 10);
            if (num >= nextNum) nextNum = num + 1;
          }
        }
      }

      // Verify the generated code doesn't already exist (handle edge cases)
      let generatedCode = `${prefix}-${String(nextNum).padStart(3, '0')}`;
      const existsCheck = await pool.query(`
        SELECT 1 FROM "${tableName}" WHERE "${codeColumn}" = $1 LIMIT 1
      `, [generatedCode]);
      if (existsCheck.rows.length > 0) {
        // Code already exists, find next truly available one
        nextNum++;
        while (true) {
          generatedCode = `${prefix}-${String(nextNum).padStart(3, '0')}`;
          const check = await pool.query(`
            SELECT 1 FROM "${tableName}" WHERE "${codeColumn}" = $1 LIMIT 1
          `, [generatedCode]);
          if (check.rows.length === 0) break;
          nextNum++;
          if (nextNum > 99999) break;
        }
      }

      res.json({ code: generatedCode, codeColumn });
    } catch (error) {
      console.error('❌ [ENTITY DATA] Next code error:', error);
      res.status(500).json({ error: 'Failed to generate next code' });
    }
  });

  // Check duplicate name in entity table
  app.get('/api/entity-data/:tableName/check-duplicate', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName } = req.params;
      const { column, value, excludeId } = req.query;
      if (!await isValidEntityTable(tableName) || !column || !value) {
        return res.json({ isDuplicate: false });
      }
      const safeCol = (column as string).replace(/[^a-zA-Z0-9_]/g, '');
      let result;
      if (excludeId) {
        result = await pool.query(`SELECT id FROM "${tableName}" WHERE LOWER(TRIM("${safeCol}")) = LOWER(TRIM($1)) AND id != $2 LIMIT 1`, [value, excludeId]);
      } else {
        result = await pool.query(`SELECT id FROM "${tableName}" WHERE LOWER(TRIM("${safeCol}")) = LOWER(TRIM($1)) LIMIT 1`, [value]);
      }
      res.json({ isDuplicate: result.rows.length > 0 });
    } catch (error) {
      res.status(500).json({ error: 'Failed to check duplicate' });
    }
  });

  // Create record in entity table
  const strictTextFieldsMap: Record<string, string[]> = {
    company_master: ['company_name', 'legal_entity_name', 'industry', 'headquarters_city', 'headquarters_state', 'headquarters_country', 'erp_system', 'primary_currency', 'status', 'record_status'],
    partner_master: ['business_unit', 'partner_name', 'partner_type', 'partner_classification', 'legal_entity_name', 'headquarters_city', 'headquarters_state', 'headquarters_country', 'primary_contact_name', 'status', 'payment_terms', 'payment_method', 'currency', 'primary_sales_channel', 'authorized_channels', 'authorized_territories', 'record_status'],
    territory_master: ['territory_name', 'territory_type', 'tax_jurisdiction', 'language', 'status', 'record_status'],
    sales_channels: ['channel_name', 'channel_type', 'channel_category', 'payment_terms_default', 'status', 'record_status'],
    partner_contract_associations: ['contract_status', 'record_status'],
    product_hierarchy: ['level_name', 'hierarchy_value', 'record_status'],
    product_classifications: ['classification_dimension', 'classification_value', 'record_status'],
    products: ['product_name', 'product_category', 'product_family', 'product_line', 'product_classification', 'asset_type', 'durability_class', 'revenue_type', 'tax_category', 'regulatory_class', 'base_unit_of_measure', 'alternate_uom_sellable', 'product_status', 'record_status'],
    product_attributes: ['attribute_name', 'attribute_category', 'record_status'],
    product_territory_matrix: ['certification_type', 'certification_status', 'record_status'],
    product_channel_matrix: ['record_status'],
    product_packaging_matrix: ['package_type', 'record_status'],
    product_bom: ['component_uom', 'bom_type', 'record_status'],
  };

  function validateStrictTextFields(tableName: string, data: Record<string, any>): string[] {
    const fields = strictTextFieldsMap[tableName] || [];
    const errors: string[] = [];
    for (const f of fields) {
      const val = data[f];
      if (val && typeof val === 'string' && /^\d+(\.\d+)?$/.test(val.trim())) {
        errors.push(f.replace(/_/g, ' '));
      }
    }
    return errors;
  }

  function validateDateSequences(data: Record<string, any>): string | null {
    if (data.effective_date && data.expiration_date) {
      if (new Date(data.expiration_date) <= new Date(data.effective_date)) {
        return 'expiration date must be later than effective date';
      }
    }
    if (data.start_date && data.end_date) {
      if (new Date(data.end_date) <= new Date(data.start_date)) {
        return 'end date must be later than start date';
      }
    }
    return null;
  }

  app.post('/api/entity-data/:tableName', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName } = req.params;
      const data = req.body;

      if (!await isValidEntityTable(tableName)) {
        return res.status(400).json({ error: `Table '${tableName}' is not accessible or not defined in schema catalog` });
      }

      const strictErrors = validateStrictTextFields(tableName, data);
      if (strictErrors.length > 0) {
        return res.status(400).json({ error: `Enter a valid text value for: ${strictErrors.join(', ')}. Numbers-only entries are not allowed.` });
      }
      const dateError = validateDateSequences(data);
      if (dateError) {
        return res.status(400).json({ error: dateError });
      }

      if (tableName === 'products') {
        const legacyMap: Record<string, { idCol: string; level: string }> = {
          product_category: { idCol: 'product_category_id', level: 'Category' },
          product_family: { idCol: 'product_family_id', level: 'Family' },
          product_line: { idCol: 'product_line_id', level: 'Line' },
        };
        for (const [textCol, { idCol, level }] of Object.entries(legacyMap)) {
          if (data[textCol] && !data[idCol]) {
            const match = await pool.query(
              `SELECT hierarchy_id FROM product_hierarchy WHERE company_id = $1 AND level_name = $2 AND LOWER(hierarchy_value) = LOWER($3) AND record_status = 'Active' LIMIT 1`,
              [data.company_id, level, data[textCol]]
            );
            if (match.rows.length > 0) data[idCol] = match.rows[0].hierarchy_id;
          }
        }
      }

      // Get valid columns for this table to validate against
      const validColumns = await getValidColumns(tableName);
      
      // Filter to only valid columns and sanitize column names
      const columns = Object.keys(data).filter(k => 
        data[k] !== undefined && 
        data[k] !== '' && 
        validColumns.has(k) && 
        isValidColumnName(k) &&
        !['id', 'created_at', 'updated_at'].includes(k) // Exclude auto-generated columns
      );
      
      if (columns.length === 0) {
        return res.status(400).json({ error: 'No valid columns provided' });
      }
      
      const values = columns.map(k => data[k]);
      const placeholders = columns.map((_, i) => `$${i + 1}`);
      
      // Use quoted identifiers to prevent SQL injection
      const quotedColumns = columns.map(c => `"${c}"`).join(', ');
      const query = `INSERT INTO "${tableName}" (${quotedColumns}) VALUES (${placeholders.join(', ')}) RETURNING *`;
      const result = await pool.query(query, values);
      
      console.log(`✅ [ENTITY DATA] Created record in ${tableName}`);
      res.json(result.rows[0]);
    } catch (error) {
      console.error('❌ [ENTITY DATA] Create error:', error);
      res.status(400).json({ error: error instanceof Error ? error.message : 'Failed to create record' });
    }
  });

  // Update record in entity table
  app.patch('/api/entity-data/:tableName/:id', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { tableName, id } = req.params;
      const data = req.body;

      if (!await isValidEntityTable(tableName)) {
        return res.status(400).json({ error: `Table '${tableName}' is not accessible or not defined in schema catalog` });
      }

      const strictErrors = validateStrictTextFields(tableName, data);
      if (strictErrors.length > 0) {
        return res.status(400).json({ error: `Enter a valid text value for: ${strictErrors.join(', ')}. Numbers-only entries are not allowed.` });
      }
      const dateError = validateDateSequences(data);
      if (dateError) {
        return res.status(400).json({ error: dateError });
      }

      if (tableName === 'products') {
        const legacyMap: Record<string, { idCol: string; level: string }> = {
          product_category: { idCol: 'product_category_id', level: 'Category' },
          product_family: { idCol: 'product_family_id', level: 'Family' },
          product_line: { idCol: 'product_line_id', level: 'Line' },
        };
        for (const [textCol, { idCol, level }] of Object.entries(legacyMap)) {
          if (data[textCol] && !data[idCol]) {
            const match = await pool.query(
              `SELECT hierarchy_id FROM product_hierarchy WHERE company_id = $1 AND level_name = $2 AND LOWER(hierarchy_value) = LOWER($3) AND record_status = 'Active' LIMIT 1`,
              [data.company_id, level, data[textCol]]
            );
            if (match.rows.length > 0) data[idCol] = match.rows[0].hierarchy_id;
          }
        }
      }

      // Get valid columns for this table to validate against
      const validColumns = await getValidColumns(tableName);
      
      // Filter to only valid columns and sanitize
      const columns = Object.keys(data).filter(k => 
        k !== 'id' && 
        data[k] !== undefined && 
        validColumns.has(k) && 
        isValidColumnName(k) &&
        !['created_at', 'updated_at'].includes(k) // Exclude auto-generated columns (updated_at set explicitly below)
      );
      
      if (columns.length === 0) {
        return res.status(400).json({ error: 'No valid columns provided for update' });
      }
      
      // Use quoted identifiers to prevent SQL injection
      const setClause = columns.map((col, i) => `"${col}" = $${i + 1}`).join(', ');
      const values = [...columns.map(k => data[k]), id];
      
      const query = `UPDATE "${tableName}" SET ${setClause}, "updated_at" = NOW() WHERE "id" = $${columns.length + 1} RETURNING *`;
      const result = await pool.query(query, values);
      
      // Sync: Update pending_term_mappings when products or vendors are updated
      if (tableName === 'products' && data.product_name) {
        await pool.query(
          `UPDATE pending_term_mappings SET erp_record_value = $1, updated_at = NOW() 
           WHERE erp_record_id = $2 AND erp_entity_name = 'Products'`,
          [data.product_name, id]
        );
        console.log(`🔄 [SYNC] Updated term mappings for product: ${id}`);
      } else if (tableName === 'partner_master' && data.partner_name) {
        await pool.query(
          `UPDATE pending_term_mappings SET erp_record_value = $1, updated_at = NOW() 
           WHERE erp_record_id = $2 AND erp_entity_name = 'Partner Master'`,
          [data.partner_name, id]
        );
        console.log(`🔄 [SYNC] Updated term mappings for partner: ${id}`);
      }
      
      console.log(`✏️ [ENTITY DATA] Updated record in ${tableName}: ${id}`);
      res.json(result.rows[0]);
    } catch (error) {
      console.error('❌ [ENTITY DATA] Update error:', error);
      res.status(400).json({ error: error instanceof Error ? error.message : 'Failed to update record' });
    }
  });

