  // =========================================================================
  // Pass 1 of AI Prompt Registry — DB-backed Flow Type & Subtype prompts
  //
  // Each row is a "starter pack" for the cascade loader. Admins can edit any
  // of the 7 prompt slots per flow code or subtype code; null/empty fields
  // fall through to the next layer (flow → contract type → built-in defaults).
  // =========================================================================
  const PROMPT_FIELDS = [
    'extractionPrompt',
    'ruleExtractionPrompt',
    'erpMappingPrompt',
    'sampleExtractionOutput',
    'ragExtractionPrompt',
    'ragRuleExtractionPrompt',
    'ragSampleExtractionOutput',
  ] as const;

  // ---------------- Flow Type Prompts -----------------
  app.get('/api/settings/flow-type-prompts', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (!req.user?.isSystemAdmin) {
        return res.status(403).json({ error: 'System Admin access required' });
      }
      const { flowTypes, flowTypePrompts } = await import('../shared/schema');
      const { DEFAULT_FLOW_TYPE_PROMPTS } = await import('./prompts/defaultFlowTypePrompts');
      const flows = await db.select({
        code: flowTypes.code,
        name: flowTypes.name,
        description: flowTypes.description,
        isActive: flowTypes.isActive,
      }).from(flowTypes);
      const promptRows = await db.select().from(flowTypePrompts);
      const byCode = new Map(promptRows.map(r => [r.flowTypeCode, r]));
      const out = flows.map(f => {
        const row = byCode.get(f.code) || null;
        const defaults = DEFAULT_FLOW_TYPE_PROMPTS[f.code] || null;
        const isCustomized = !!row && PROMPT_FIELDS.some(field => {
          const v = (row as any)[field];
          const d = defaults ? (defaults as any)[field] : null;
          return v != null && v !== '' && v !== d;
        });
        return {
          flowTypeCode: f.code,
          flowTypeName: f.name,
          description: f.description,
          flowTypeIsActive: f.isActive,
          hasDefaults: !!defaults,
          isCustomized,
          prompts: row || (defaults ? { flowTypeCode: f.code, ...defaults, isActive: true } : null),
        };
      });
      res.json({ entries: out });
    } catch (e: any) {
      console.error('Error fetching flow-type prompts:', e);
      res.status(500).json({ error: e.message });
    }
  });

  app.put('/api/settings/flow-type-prompts/:flowTypeCode', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (!req.user?.isSystemAdmin) {
        return res.status(403).json({ error: 'System Admin access required' });
      }
      const { flowTypeCode } = req.params;
      const { flowTypes, flowTypePrompts } = await import('../shared/schema');
      const [exists] = await db.select({ code: flowTypes.code }).from(flowTypes).where(eq(flowTypes.code, flowTypeCode)).limit(1);
      if (!exists) return res.status(404).json({ error: `Flow type ${flowTypeCode} not found` });

      const updates: Record<string, any> = {};
      for (const field of PROMPT_FIELDS) {
        if (field in req.body) {
          const v = req.body[field];
          updates[field] = (typeof v === 'string' && v.trim()) ? v.trim() : null;
        }
      }
      if (typeof req.body.isActive === 'boolean') updates.isActive = req.body.isActive;

      const [existing] = await db.select().from(flowTypePrompts).where(eq(flowTypePrompts.flowTypeCode, flowTypeCode)).limit(1);
      if (existing) {
        await db.update(flowTypePrompts)
          .set({ ...updates, updatedAt: new Date() })
          .where(eq(flowTypePrompts.flowTypeCode, flowTypeCode));
      } else {
        await db.insert(flowTypePrompts).values({ flowTypeCode, ...updates, isActive: updates.isActive ?? true });
      }
      res.json({ success: true, flowTypeCode });
    } catch (e: any) {
      console.error('Error updating flow-type prompt:', e);
      res.status(500).json({ error: e.message });
    }
  });

