  app.get('/api/contracts/:id/template-validation', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { id } = req.params;
      
      const [contract] = await db.select()
        .from(contracts)
        .where(eq(contracts.id, id))
        .limit(1);
      
      if (!contract) {
        return res.status(404).json({ error: 'Contract not found' });
      }
      
      const contractTypeCode = contract.contractSubtype || contract.contract_type || '';
      const template = await ruleTemplateService.getTemplateForContractType(contractTypeCode);
      
      if (!template) {
        return res.json({
          contractId: id,
          contractTypeCode,
          hasTemplate: false,
          validation: null,
          message: `No rule template defined for contract type "${contractTypeCode}"`,
        });
      }
      
      const existingRules = await db.select()
        .from(contractRules)
        .where(eq(contractRules.contractId, id));
      
      const rulesToValidate = existingRules.map(r => ({
        ruleName: r.ruleName || '',
        ruleType: r.ruleType || '',
        baseRate: typeof r.baseRate === 'string' ? parseFloat(r.baseRate) : (r.baseRate as number) || 0,
        qualifiers: (r.qualifiers as any[]) || [],
        priority: r.priority || 1,
        description: r.description || '',
      }));
      
      const validation = ruleTemplateService.validateExtractedRules(rulesToValidate, template);
      
      res.json({
        contractId: id,
        contractTypeCode,
        hasTemplate: true,
        validation,
      });
    } catch (error) {
      console.error('Error validating rules:', error);
      res.status(500).json({ error: 'Failed to validate rules' });
    }
  });

