      const responseSettings: any = { ...settings };
      const dbPassword = responseSettings.smtpPassword;
      const envPassword = process.env.ZOHO_PASSWORD;
      if (dbPassword) {
        responseSettings.smtpPasswordSet = true;
        responseSettings.smtpPassword = dbPassword;
        responseSettings.smtpPasswordSource = 'database';
      } else if (envPassword) {
        responseSettings.smtpPasswordSet = true;
        responseSettings.smtpPassword = envPassword;
        responseSettings.smtpPasswordSource = 'environment';
      } else {
        responseSettings.smtpPasswordSet = false;
        responseSettings.smtpPassword = '';
        responseSettings.smtpPasswordSource = 'none';
      }
      const prompts = (settings.extractionPrompts as Record<string, any>) || {};
      responseSettings.featureFlagAiExtraction = prompts.featureFlagAiExtraction ?? true;
