  // Update system settings
  app.put('/api/settings/system', isAuthenticated, async (req: any, res: Response) => {
    try {
      if (!req.user?.isSystemAdmin) {
        return res.status(403).json({ error: 'System Admin access required' });
      }

      const fieldMap: Record<string, string> = {
        maxRetriesAi: 'aiRetryAttempts',
        confidenceThresholdHigh: 'autoConfirmThreshold',
        confidenceThresholdMedium: 'lowConfidenceThreshold',
        sessionTimeout: 'sessionTimeoutMinutes',
        requireMfa: 'require2FA',
        enableAuditLog: 'enableAuditLogging',
      };

      const jsonbFields = new Set([
        'featureFlagAiExtraction', 'featureFlagRagQa', 'featureFlagErpIntegration', 'featureFlagMultiLocation',
        'featureFlagErpMatching',
        'extractionPromptTemplate', 'mappingPromptTemplate', 'riskAssessmentPromptTemplate',
        'summaryPromptTemplate', 'riskAnalysisPromptTemplate', 'businessInsightsPromptTemplate', 'keyTermsPromptTemplate',
      ]);

      const ignoredFields = ['aiTimeout'];

      const validColumns = new Set([
        'aiProvider', 'aiModel', 'aiTemperature', 'aiMaxTokens', 'aiRetryAttempts',
        'autoConfirmThreshold', 'lowConfidenceThreshold',
        'defaultExtractionMode', 'analysisMode', 'defaultEvaluationMode',
        'sessionTimeoutMinutes', 'maxLoginAttempts', 'passwordMinLength', 'require2FA',
        'maxFileSizeMB', 'allowedFileTypes', 'fileRetentionDays',
        'enableBetaFeatures', 'enableAuditLogging', 'enableEmailNotifications',
        'apiRateLimitPerMinute', 'extractionPrompts',
        'smtpHost', 'smtpPort', 'smtpSecure', 'smtpUser', 'smtpPassword',
        'smtpFromName', 'smtpFromEmail',
        'defaultObligationAccrualBasis',
        'obligationExpirySweepEnabled', 'obligationExpirySweepHourUtc',
      ]);

      const mapped: Record<string, any> = {};
      const jsonbUpdates: Record<string, any> = {};
      for (const [key, value] of Object.entries(req.body)) {
        if (ignoredFields.includes(key)) continue;
        if (key === 'smtpPassword' && (!value || value === '')) continue;
        if (jsonbFields.has(key)) {
          jsonbUpdates[key] = value;
          continue;
        }
        const mappedKey = fieldMap[key] || key;
        if (validColumns.has(mappedKey)) {
          mapped[mappedKey] = value;
        }
      }

      // Validate the obligation expiry sweep hour: must be an integer 0–23.
      // The in-process scheduler ticks every 5 min and fires when the
      // current UTC hour reaches this value, so an out-of-range value would
      // either disable the sweep entirely or run it at the wrong time.
      if (mapped.obligationExpirySweepHourUtc !== undefined) {
        const h = Number(mapped.obligationExpirySweepHourUtc);
        if (!Number.isInteger(h) || h < 0 || h > 23) {
          return res.status(400).json({ error: 'obligationExpirySweepHourUtc must be an integer between 0 and 23' });
        }
        mapped.obligationExpirySweepHourUtc = h;
      }

      if (Object.keys(jsonbUpdates).length > 0) {
        const existing = await storage.getSystemSettings();
        const existingPrompts = (existing?.extractionPrompts as Record<string, any>) || {};
        mapped.extractionPrompts = { ...existingPrompts, ...jsonbUpdates };
      }

      const settings = await storage.updateSystemSettings(mapped as any);
      
      const responseSettings: any = { ...settings };
      const prompts = (settings.extractionPrompts as Record<string, any>) || {};
      responseSettings.featureFlagAiExtraction = prompts.featureFlagAiExtraction ?? true;
      responseSettings.featureFlagRagQa = prompts.featureFlagRagQa ?? true;
      responseSettings.featureFlagErpIntegration = prompts.featureFlagErpIntegration ?? true;
      responseSettings.featureFlagMultiLocation = prompts.featureFlagMultiLocation ?? true;
      responseSettings.featureFlagErpMatching = prompts.featureFlagErpMatching ?? false;
      responseSettings.extractionPromptTemplate = prompts.extractionPromptTemplate ?? '';
      responseSettings.mappingPromptTemplate = prompts.mappingPromptTemplate ?? '';
      responseSettings.riskAssessmentPromptTemplate = prompts.riskAssessmentPromptTemplate ?? '';
      responseSettings.summaryPromptTemplate = prompts.summaryPromptTemplate ?? '';
      responseSettings.riskAnalysisPromptTemplate = prompts.riskAnalysisPromptTemplate ?? '';
      responseSettings.businessInsightsPromptTemplate = prompts.businessInsightsPromptTemplate ?? '';
      responseSettings.keyTermsPromptTemplate = prompts.keyTermsPromptTemplate ?? '';
      res.json(responseSettings);
    } catch (error) {
      console.error('Error updating system settings:', error);
      res.status(500).json({ error: 'Failed to update system settings' });
    }
  });

