  // ==========================================
  // CITY LOOKUP (from city_master/state_master/country_master)
  // ==========================================
  app.get('/api/reference/cities', isAuthenticated, async (req: any, res: Response) => {
    try {
      const q = ((req.query.q as string) || '').trim();
      const limit = Math.min(parseInt(req.query.limit as string) || 20, 100);
      if (!q || q.length < 1) {
        return res.json([]);
      }
      const searchTerm = `%${q}%`;
      const result = await pool.query(
        `SELECT c.id AS "cityId", c.city_name AS city, c.postal_code AS "postalCode",
                s.state_name AS state, s.state_code AS "stateCode",
                co.country_name AS country, co.country_code AS "countryCode"
         FROM city_master c
         JOIN state_master s ON c.state_id = s.id
         JOIN country_master co ON s.country_id = co.id
         WHERE c.city_name ILIKE $1
            OR c.postal_code ILIKE $1
            OR s.state_name ILIKE $1
            OR s.state_code ILIKE $1
            OR co.country_name ILIKE $1
            OR co.country_code ILIKE $1
         ORDER BY c.city_name, s.state_name, co.country_name, c.postal_code
         LIMIT $2`,
        [searchTerm, limit]
      );
      res.json(result.rows);
    } catch (error: any) {
      console.error('City lookup error:', error);
      res.status(500).json({ message: error.message });
    }
  });

