  app.put('/api/contracts/:id/master', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const existing = await db.select().from(contracts).where(eq(contracts.id, contractId)).limit(1);
      if (existing.length === 0) {
        return res.status(404).json({ message: 'Contract not found' });
      }
      const body = { ...req.body };
      const updates: any = { updatedAt: new Date() };
      if (body.contractName !== undefined) updates.displayName = body.contractName;
      if (body.contractType !== undefined) updates.contractType = body.contractType;
      if (body.contractCategory !== undefined) updates.contractCategory = body.contractCategory;
      if (body.effectiveDate !== undefined) updates.effectiveStart = body.effectiveDate ? new Date(body.effectiveDate) : null;
      if (body.expirationDate !== undefined) updates.effectiveEnd = body.expirationDate ? new Date(body.expirationDate) : null;
      if (body.autoRenew !== undefined) updates.autoRenew = body.autoRenew;
      if (body.renewalTermMonths !== undefined) updates.renewalTermMonths = body.renewalTermMonths;
      if (body.territoryScope !== undefined) updates.territoryScope = body.territoryScope;
      if (body.channelScope !== undefined) updates.channelScope = body.channelScope;
      if (body.owningParty !== undefined) { updates.owningParty = body.owningParty; updates.organizationName = body.owningParty; }
      if (body.counterpartyType !== undefined) updates.counterpartyType = body.counterpartyType;
      if (body.contractStatus !== undefined) updates.contractStatus = body.contractStatus;
      if (body.contractValueEstimatedAnnual !== undefined) updates.contractValueEstimatedAnnual = body.contractValueEstimatedAnnual;
      if (body.currency !== undefined) updates.currency = body.currency;
      if (body.paymentFrequency !== undefined) updates.paymentFrequency = body.paymentFrequency;
      if (body.notes !== undefined) updates.notes = body.notes;

      // Pre-activation guard: block any save that would leave the contract
      // in "Active" state with unmet requirements. Fires when the request
      // sets status to active OR when the contract is already active and is
      // being re-saved.
      const targetStatus = (updates.contractStatus !== undefined
        ? (updates.contractStatus || '').toString().toLowerCase()
        : (existing[0].contractStatus || '').toString().toLowerCase());
      if (targetStatus === 'active') {
        const { validateContractForActivation, formatFailureSummary } = await import('./services/contractValidation');
        const result = await validateContractForActivation(contractId);
        if (!result.valid) {
          return res.status(422).json({
            error: `Cannot save contract as Active — ${result.failures.length} validation issue${result.failures.length === 1 ? '' : 's'} must be resolved first.`,
            code: 'CONTRACT_VALIDATION_FAILED',
            failures: result.failures,
            summary: formatFailureSummary(result.failures),
          });
        }
      }

      const [updated] = await db.update(contracts)
        .set(updates)
        .where(eq(contracts.id, contractId))
        .returning();
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.get('/api/contracts/:id/terms', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const { validateContractAccess } = await import('./utils/contractAccess');
      const { contract, authorized, error } = await validateContractAccess(contractId, req.user);
      if (!contract) return res.status(404).json({ message: error || 'Contract not found' });
      if (!authorized) return res.status(403).json({ message: error || 'Access denied' });
      const terms = await db.select().from(contractTermsTable)
        .where(eq(contractTermsTable.contractId, contractId))
        .orderBy(contractTermsTable.termSequence);
      
      const termsWithTiers = await Promise.all(terms.map(async (term) => {
        if (term.linkedRuleId) {
          const [rule] = await db.select({ volumeTiers: contractRules.volumeTiers, formulaDefinition: contractRules.formulaDefinition })
            .from(contractRules)
            .where(eq(contractRules.id, term.linkedRuleId))
            .limit(1);
          if (rule) {
            return { ...term, volumeTiers: rule.volumeTiers, formulaDefinition: rule.formulaDefinition };
          }
        }
        return { ...term, volumeTiers: null, formulaDefinition: null };
      }));
      res.json(termsWithTiers);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

