  app.put('/api/contract-partners/:assignmentId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { assignmentId } = req.params;
      const [parent] = await db.select({ contractId: contractPartnerAssignmentsTable.contractId })
        .from(contractPartnerAssignmentsTable)
        .where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId));
      if (parent && await sendIfLocked(res, parent.contractId)) return;
      const updates: any = { ...req.body };
      delete updates.assignmentId;
      delete updates.contractId;
      delete updates.resolved_name;
      delete updates.resolved_kind;
      delete updates.partner_name;
      // Coerce date fields: empty string -> null, ISO string -> Date.
      // Drizzle's timestamp column calls .toISOString() and chokes on "".
      const coerceDate = (v: any) => {
        if (v === '' || v === null || v === undefined) return null;
        if (v instanceof Date) return v;
        const d = new Date(v);
        return isNaN(d.getTime()) ? null : d;
      };
      if ('effectiveStart' in updates) updates.effectiveStart = coerceDate(updates.effectiveStart);
      if ('effectiveEnd' in updates) updates.effectiveEnd = coerceDate(updates.effectiveEnd);
      // Drop array/snake_case junk that isn't a column. We allow camelCase
      // forms (partyKind, partyRole, isPrimary, etc.) through so a placeholder
      // row being promoted to a real role can have its kind set in the same
      // call — otherwise party_kind stays NULL on every promoted assignment,
      // which then breaks the Parties tab's per-party grouping (a NULL kind
      // resolves to the wrong id column → group has no master id → required-
      // role chips show red even though the assignment is properly linked).
      delete updates.partyRoles;
      delete updates.effective_start;
      delete updates.effective_end;
      delete updates.party_role;
      delete updates.party_kind;
      delete updates.assignment_type;
      delete updates.is_primary;
      delete updates.custom_terms;
      delete updates.raw_value;
      delete updates.link_status;
      delete updates.link_confidence;
      delete updates.link_method;
      // If the promoted row has an id but no kind, infer it from which id is set.
      if (!updates.partyKind) {
        if (updates.companyId) updates.partyKind = 'organization';
        else if (updates.partnerId) updates.partyKind = 'partner';
      }
      // If user picked a master record, mark link as manual unless explicitly set.
      if ((updates.partnerId || updates.companyId) && !updates.linkStatus) {
        updates.linkStatus = 'manual';
        updates.linkMethod = updates.linkMethod ?? 'manual';
      }
      const [updated] = await db.update(contractPartnerAssignmentsTable)
        .set(updates)
        .where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId))
        .returning();
      if (!updated) {
        return res.status(404).json({ message: 'Partner assignment not found' });
      }
      // Reverse-sync: any change to a primary counterparty/owning_party row
      // should propagate back to the contracts table metadata.
      if (
        updated.isPrimary &&
        (updated.partyRole === 'counterparty' || updated.partyRole === 'owning_party') &&
        updated.contractId
      ) {
        try {
          const { syncContractMetadataFromPartyRoles } = await import("./services/partyRoleService");
          await syncContractMetadataFromPartyRoles(updated.contractId);
        } catch (e: any) {
          console.warn("Reverse metadata sync failed (non-fatal):", e.message);
        }
      }
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // PATCH /api/contract-partners/:assignmentId/link
  // Same shape LinkedMasterField speaks: { action: 'confirm'|'set'|'unlink',
  // partnerId?/partnerName? OR companyId?/companyName?, confidence?, method? }.
  // Routes the update to the right master-id column based on which id was sent.
  app.patch('/api/contract-partners/:assignmentId/link', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { assignmentId } = req.params;
      const userId = req.user.id;
      const { action, partnerId, partnerName, companyId, companyName, confidence, method } = req.body || {};

      const [existing] = await db.select().from(contractPartnerAssignmentsTable)
        .where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId));
      if (!existing) return res.status(404).json({ error: 'Partner assignment not found' });
      if (await sendIfLocked(res, existing.contractId)) return;

      const updates: any = {};
      if (action === 'unlink') {
        updates.partnerId = null;
        updates.companyId = null;
        updates.linkStatus = 'unlinked';
        updates.linkConfidence = null;
        updates.linkMethod = null;
      } else if (action === 'confirm' || action === 'set') {
        const isPartner = !!partnerId;
        const isCompany = !!companyId;
        if (!isPartner && !isCompany) {
          return res.status(400).json({ error: 'partnerId or companyId is required' });
        }
        if (isPartner) {
          updates.partnerId = partnerId;
          updates.companyId = null;
          updates.partnerName = partnerName ?? existing.partnerName;
        } else {
          updates.companyId = companyId;
          updates.partnerId = null;
          updates.partnerName = companyName ?? existing.partnerName;
        }
        updates.linkStatus = action === 'set' ? 'manual' : 'verified';
        updates.linkConfidence = action === 'set' ? 1.0 : (confidence ?? 1.0);
        updates.linkMethod = action === 'set' ? 'manual' : (method ?? 'manual');
      } else {
        return res.status(400).json({ error: 'action must be one of: confirm, set, unlink' });
      }

      const [updated] = await db.update(contractPartnerAssignmentsTable)
        .set(updates)
        .where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId))
        .returning();

      // Reverse-sync metadata if we just changed a primary counterparty/owning_party row.
      if (
        updated?.isPrimary &&
        (updated.partyRole === 'counterparty' || updated.partyRole === 'owning_party') &&
        updated.contractId
      ) {
        try {
          const { syncContractMetadataFromPartyRoles } = await import("./services/partyRoleService");
          await syncContractMetadataFromPartyRoles(updated.contractId);
        } catch (e: any) {
          console.warn("Reverse metadata sync failed (non-fatal):", e.message);
        }
      }

      res.json(updated);
    } catch (error: any) {
      console.error('Partner-link PATCH error:', error);
      res.status(500).json({ error: error.message || 'Failed to update partner link' });
    }
  });

  app.delete('/api/contract-partners/:assignmentId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { assignmentId } = req.params;
      // Read the row first so we can decide whether to re-sync metadata after delete.
      const [existing] = await db
        .select()
        .from(contractPartnerAssignmentsTable)
        .where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId));
      if (existing && await sendIfLocked(res, existing.contractId)) return;
      await db.delete(contractPartnerAssignmentsTable).where(eq(contractPartnerAssignmentsTable.assignmentId, assignmentId));
      if (
        existing?.isPrimary &&
        (existing.partyRole === 'counterparty' || existing.partyRole === 'owning_party') &&
        existing.contractId
      ) {
        try {
          const { syncContractMetadataFromPartyRoles } = await import("./services/partyRoleService");
          await syncContractMetadataFromPartyRoles(existing.contractId);
        } catch (e: any) {
          console.warn("Reverse metadata sync failed (non-fatal):", e.message);
        }
      }
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // ====== Manual Contract Creation (no file upload) ======

  app.post('/api/contracts/create-manual', isAuthenticated, async (req: any, res: Response) => {
    try {
      const userId = req.user?.id;
      if (!userId) return res.status(401).json({ message: 'Not authenticated' });
      
      const {
        displayName, contractType, contractSubtype, priority, notes,
        organizationName, counterpartyName, effectiveStart, effectiveEnd,
        renewalTerms, governingLaw,
        territoryScope, channelScope, paymentFrequency, contractCategory,
        contractStatus, currency, autoRenew, contractValueEstimated, companyId
      } = req.body;

      if (!displayName) {
        return res.status(400).json({ message: 'Contract name is required' });
      }

      // Server-side duplicate name check
      const duplicateCheck = await db.execute(sql`SELECT id, display_name FROM contracts WHERE LOWER(TRIM(display_name)) = LOWER(TRIM(${displayName})) LIMIT 1`);
      if (duplicateCheck.rows && duplicateCheck.rows.length > 0) {
        return res.status(409).json({ message: `A contract with the name "${displayName}" already exists. Please use a unique contract name.` });
      }

      const resolvedCompanyId = companyId || req.user?.activeContext?.companyId || req.user?.companyId || null;

      const year = new Date().getFullYear();
      const prefix = `CNT-${year}-`;
      const maxResult = await db.execute(sql`SELECT MAX(CAST(NULLIF(regexp_replace(contract_number, ${prefix}, ''), '') AS INTEGER)) as max_num FROM contracts WHERE contract_number ~ ${`^${prefix}\\d+$`}`);
      const nextNum = (Number((maxResult.rows?.[0] as any)?.max_num) || 0) + 1;
      let contractNumber = `CNT-${year}-${String(nextNum).padStart(3, '0')}`;

      const existingCheck = await db.execute(sql`SELECT 1 FROM contracts WHERE contract_number = ${contractNumber} LIMIT 1`);
      if (existingCheck.rows && existingCheck.rows.length > 0) {
        contractNumber = `CNT-${year}-${String(nextNum + 1).padStart(3, '0')}`;
      }

      const [newContract] = await db.insert(contracts).values({
        contractNumber,
        fileName: 'manual-entry',
        originalName: displayName,
        fileSize: 0,
        fileType: 'manual',
        filePath: '',
        source: 'manual',
        contractType: contractType || null,
        contractSubtype: contractSubtype || null,
        priority: priority || 'normal',
        status: 'analyzed',
        uploadedBy: userId,
        notes: notes || null,
        displayName,
        effectiveStart: effectiveStart ? new Date(effectiveStart) : null,
        effectiveEnd: effectiveEnd ? new Date(effectiveEnd) : null,
        renewalTerms: renewalTerms || null,
        governingLaw: governingLaw || null,
        organizationName: organizationName || null,
        counterpartyName: counterpartyName || null,
        companyId: resolvedCompanyId,
        contractCategory: contractCategory || null,
        autoRenew: autoRenew || false,
        territoryScope: territoryScope || null,
        channelScope: channelScope || null,
        owningParty: organizationName || null,
        counterpartyType: counterpartyName || null,
        contractStatus: contractStatus || 'Draft',
        contractValueEstimatedAnnual: contractValueEstimated || null,
        currency: currency || 'USD',
        paymentFrequency: paymentFrequency || null,
      }).returning();

      if (counterpartyName && newContract) {
        try {
          const assignmentId = `ASSIGN-AUTO-${Date.now()}`;
          await db.insert(contractPartnerAssignmentsTable).values({
            assignmentId,
            contractId: newContract.id,
            partnerId: counterpartyName,
            assignmentType: 'Primary',
            status: 'active',
            customTerms: false,
            notes: 'Auto-created from counterparty during contract creation',
          });
        } catch (partnerErr: any) {
          console.warn('Auto-create partner assignment failed (non-critical):', partnerErr.message);
        }
      }

      res.json(newContract);
    } catch (error: any) {
      console.error('Error creating manual contract:', error);
      res.status(500).json({ message: error.message });
    }
  });

  // ====== Generate AI-Contextual Sample Data for Manual Contracts ======
  app.post('/api/contracts/:id/generate-sample-data', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const { tabType } = req.body;
      if (!tabType) return res.status(400).json({ message: 'tabType is required' });

      const [contract] = await db.select().from(contracts).where(eq(contracts.id, contractId)).limit(1);
      if (!contract) return res.status(404).json({ message: 'Contract not found' });

      const { generateContextualRules, generateContextualClauses, generateContextualAnalysis, generateContextualQualifiers, selectContextualPartners, fetchMasterDataCatalog } = await import('./services/contextualSampleService.js');

      const ctx = {
        contractName: contract.displayName || contract.originalName || 'Unnamed Contract',
        contractType: contract.contractType || 'royalty_license',
        contractSubtype: (contract as any).contractSubtype || '',
        organization: contract.organizationName || 'Company A',
        counterparty: contract.counterpartyName || 'Company B',
        startDate: contract.effectiveStart ? new Date(contract.effectiveStart).toISOString().split('T')[0] : '2026-01-01',
        endDate: contract.effectiveEnd ? new Date(contract.effectiveEnd).toISOString().split('T')[0] : '2028-12-31',
        territoryScope: (contract as any).territoryScope || '',
        channelScope: (contract as any).channelScope || '',
        currency: (contract as any).currency || 'USD',
      };

      const catalog = await fetchMasterDataCatalog();

      if (tabType === 'analysis') {
        const analysis = await generateContextualAnalysis(ctx, catalog);
        const existing = await db.select().from(contractAnalysis).where(eq(contractAnalysis.contractId, contractId)).limit(1);
        if (existing.length > 0) {
          await db.update(contractAnalysis).set({
            summary: analysis.summary,
            keyTerms: analysis.keyTerms as any,
            riskAnalysis: analysis.riskAnalysis as any,
            insights: analysis.insights as any,
          }).where(eq(contractAnalysis.contractId, contractId));
        } else {
          await db.insert(contractAnalysis).values({
            contractId,
            summary: analysis.summary,
            keyTerms: analysis.keyTerms as any,
            riskAnalysis: analysis.riskAnalysis as any,
            insights: analysis.insights as any,
          });
        }
        return res.json({ success: true, data: analysis, message: 'AI-contextual analysis generated successfully' });
      }

      if (tabType === 'rules') {
        await db.delete(contractRules).where(eq(contractRules.contractId, contractId));
        const rules = await generateContextualRules(ctx, catalog);

        const insertedRules = [];
        for (const rule of rules) {
          const [inserted] = await db.insert(contractRules).values({
            contractId,
            ...rule,
            isActive: true,
            companyId: contract.companyId,
            effectiveDate: rule.effectiveDate || (contract.effectiveStart ? new Date(contract.effectiveStart) : null),
            expiryDate: rule.expiryDate || (contract.effectiveEnd ? new Date(contract.effectiveEnd) : null),
            channel: rule.channel || 'All',
          } as any).returning();
          insertedRules.push(inserted);
        }
        return res.json({ success: true, data: insertedRules, count: insertedRules.length, message: `${insertedRules.length} AI-contextual rules generated from master data` });
      }

      if (tabType === 'clauses') {
        await db.delete(contractClauses).where(eq(contractClauses.contractId, contractId));
        const clauses = await generateContextualClauses(ctx, catalog);

        const insertedClauses = [];
        for (let i = 0; i < clauses.length; i++) {
          const cl = clauses[i];
          const [inserted] = await db.insert(contractClauses).values({
            contractId,
            text: cl.text,
            clauseIdentifier: `CL-${String(i + 1).padStart(3, '0')}`,
            sectionRef: cl.sectionRef,
            clauseCategoryCode: cl.clauseCategoryCode,
            flowTypeCode: cl.flowTypeCode,
            confidence: cl.confidence || 85 + Math.floor(Math.random() * 15),
          } as any).returning();
          insertedClauses.push(inserted);
        }
        return res.json({ success: true, data: insertedClauses, count: insertedClauses.length, message: `${insertedClauses.length} AI-contextual clauses generated` });
      }

      if (tabType === 'terms') {
        const masterId = contract.contractNumber || contractId;
        await db.delete(contractQualifiersTable).where(sql`term_id IN (SELECT term_id FROM contract_terms WHERE contract_id = ${masterId})`);
        await db.delete(contractTermsTable).where(eq(contractTermsTable.contractId, masterId));

        const territories = catalog.territories.sort(() => Math.random() - 0.5).slice(0, 3);
        const channels = catalog.channels.sort(() => Math.random() - 0.5).slice(0, 2);
        const products = catalog.productCategories.sort(() => Math.random() - 0.5).slice(0, 2);
        const effDate = ctx.startDate ? new Date(ctx.startDate) : null;
        const expDate = ctx.endDate ? new Date(ctx.endDate) : null;

        const termsList = [
          { termId: `TRM-${masterId}-001`, termName: 'Base Fee Rate', termSequence: 1, termType: 'rate', rateType: 'percentage', rateValue: '6.5', appliesToTerritory: territories[0] || null, appliesToChannel: channels[0] || null, appliesToProductCategory: products[0] || null, effectiveDate: effDate, expirationDate: expDate, notes: 'Standard percentage fee applied to net revenue' },
          { termId: `TRM-${masterId}-002`, termName: 'Minimum Quarterly Guarantee', termSequence: 2, termType: 'minimum', rateType: 'flat', rateValue: '50000', appliesToTerritory: territories[1] || territories[0] || null, effectiveDate: effDate, expirationDate: expDate, notes: 'Minimum payment due per quarter' },
          { termId: `TRM-${masterId}-003`, termName: 'Payment Terms', termSequence: 3, termType: 'payment', paymentTiming: 'Net 45', paymentMethod: 'Wire Transfer', effectiveDate: effDate, expirationDate: expDate, notes: 'Net payment due days after quarter end' },
          { termId: `TRM-${masterId}-004`, termName: 'Annual Fee Cap', termSequence: 4, termType: 'cap', rateType: 'flat', rateValue: '500000', appliesToProductCategory: products[1] || products[0] || null, effectiveDate: effDate, expirationDate: expDate, notes: 'Maximum annual fee payment limit' },
          { termId: `TRM-${masterId}-005`, termName: 'Late Payment Interest', termSequence: 5, termType: 'penalty', rateType: 'percentage', rateValue: '1.5', appliesToChannel: channels[1] || channels[0] || null, effectiveDate: effDate, expirationDate: expDate, notes: 'Monthly interest rate on overdue payments' },
        ];

        const insertedTerms = [];
        for (const term of termsList) {
          const [inserted] = await db.insert(contractTermsTable).values({ contractId: masterId, ...term } as any).returning();
          insertedTerms.push(inserted);
        }
        return res.json({ success: true, data: insertedTerms, count: insertedTerms.length, message: `${insertedTerms.length} terms generated from master data` });
      }

      if (tabType === 'qualifiers') {
        const masterId = contract.contractNumber || contractId;
        await db.delete(contractQualifiersTable).where(sql`term_id IN (SELECT term_id FROM contract_terms WHERE contract_id = ${masterId})`);
        let existingTerms = await db.select().from(contractTermsTable).where(eq(contractTermsTable.contractId, masterId));

        if (existingTerms.length === 0) {
          const autoTerms = [
            { termId: `TRM-${masterId}-AUTO-001`, termName: 'Base Rate Term', termSequence: 1, termType: 'rate' },
            { termId: `TRM-${masterId}-AUTO-002`, termName: 'Payment Term', termSequence: 2, termType: 'payment' },
          ];
          for (const t of autoTerms) {
            const [ins] = await db.insert(contractTermsTable).values({ contractId: masterId, ...t } as any).returning();
            existingTerms.push(ins);
          }
        }

        const qualifiers = await generateContextualQualifiers(ctx, catalog);
        const insertedQualifiers = [];
        for (let i = 0; i < qualifiers.length; i++) {
          const q = qualifiers[i];
          const linkedTerm = existingTerms[i % existingTerms.length];
          const qualifierId = `QL-${masterId}-${String(i + 1).padStart(3, '0')}`;
          const [inserted] = await db.insert(contractQualifiersTable).values({
            qualifierId, termId: linkedTerm.termId, contractId, ...q,
          } as any).returning();
          insertedQualifiers.push(inserted);
        }
        return res.json({ success: true, data: insertedQualifiers, count: insertedQualifiers.length, message: `${insertedQualifiers.length} AI-contextual qualifiers generated from master data` });
      }

      if (tabType === 'partners') {
        const masterId = contract.contractNumber || contractId;
        await db.delete(contractPartnerAssignmentsTable).where(eq(contractPartnerAssignmentsTable.contractId, masterId));

        const selectedPartners = await selectContextualPartners(ctx, catalog);
        if (selectedPartners.length === 0) {
          return res.json({ success: true, data: [], count: 0, message: 'No partners available in master data to assign' });
        }

        const insertedPartners = [];
        for (let i = 0; i < selectedPartners.length; i++) {
          const sp = selectedPartners[i];
          const pmResult = await db.execute(sql`SELECT id FROM partner_master WHERE partner_name = ${sp.name} LIMIT 1`);
          const partnerId = (pmResult.rows?.[0] as any)?.id || sp.name;
          const assignmentId = `PA-${masterId}-${i + 1}`;
          const [inserted] = await db.insert(contractPartnerAssignmentsTable).values({
            assignmentId,
            contractId: masterId,
            partnerId: sp.name,
            assignmentType: sp.assignmentType,
            effectiveDate: ctx.startDate ? new Date(ctx.startDate) : null,
            expirationDate: ctx.endDate ? new Date(ctx.endDate) : null,
            status: 'active',
            notes: `${sp.type} - AI selected for ${ctx.contractType} contract`,
          } as any).returning();
          insertedPartners.push(inserted);
        }
        return res.json({ success: true, data: insertedPartners, count: insertedPartners.length, message: `${insertedPartners.length} AI-contextual partners assigned from master data` });
      }

      return res.status(400).json({ message: `Unknown tab type: ${tabType}` });
    } catch (error: any) {
      console.error('Error generating sample data:', error);
      res.status(500).json({ message: error.message });
    }
  });

