  app.put('/api/contract-clauses/:clauseId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { clauseId } = req.params;
      const [parent] = await db.select({ contractId: contractClauses.contractId })
        .from(contractClauses).where(eq(contractClauses.id, clauseId));
      if (parent && await sendIfLocked(res, parent.contractId)) return;
      const updates = { ...req.body };
      delete updates.id;
      delete updates.contractId;
      if (updates.confidence) updates.confidence = parseFloat(updates.confidence);
      const [updated] = await db.update(contractClauses)
        .set(updates)
        .where(eq(contractClauses.id, clauseId))
        .returning();
      if (!updated) return res.status(404).json({ message: 'Clause not found' });
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

