  // ====== Contract Fee Rules (contract_rules) CRUD ======
  app.get('/api/contracts/:id/rules-list', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const showAll = req.query.showAll === 'true';
      const rules = await db.select().from(contractRules)
        .where(showAll 
          ? eq(contractRules.contractId, contractId)
          : and(eq(contractRules.contractId, contractId), eq(contractRules.isActive, true))
        )
        .orderBy(contractRules.extractionOrder);
      const enriched = rules.map(r => {
        const cats: string[] = r.productCategories || [];
        const exclusions: string[] = [];
        for (const c of cats) {
          if (c.startsWith('!')) {
            exclusions.push(c.substring(1));
          }
        }
        return {
          ...r,
          exclusionCategories: exclusions,
        };
      });
      res.json(enriched);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post('/api/contracts/:id/rules-list', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      const {
        ruleType, ruleName, description, baseRate, minimumGuarantee,
        calculationFormula, productCategories, territories,
        volumeTiers, seasonalAdjustments, territoryPremiums,
        priority, clauseCategory, customerSegments, partnerIds, channel,
        sourceSection, sourceText, effectiveDate, expiryDate,
        templateCode, executionGroup, baseMetric, confidence,
        milestones, milestoneCount, milestoneTiers, milestoneConfig,
        calcPhase, triggerSource, aggregationScope,
        subtypeInstanceId, formulaDefinition,
      } = req.body;

      if (!ruleName || !ruleType) {
        return res.status(400).json({ message: 'Rule name and type are required' });
      }

      let resolvedEffectiveDate = effectiveDate ? new Date(effectiveDate) : null;
      let resolvedExpiryDate = expiryDate ? new Date(expiryDate) : null;
      let resolvedChannel = channel || null;

      if (!resolvedEffectiveDate || !resolvedExpiryDate || !resolvedChannel) {
        const [parentContract] = await db.select({
          effectiveStart: contracts.effectiveStart,
          effectiveEnd: contracts.effectiveEnd,
          channelScope: contracts.channelScope,
        }).from(contracts).where(eq(contracts.id, contractId)).limit(1);
        if (parentContract) {
          if (!resolvedEffectiveDate && parentContract.effectiveStart) {
            resolvedEffectiveDate = new Date(parentContract.effectiveStart);
          }
          if (!resolvedExpiryDate && parentContract.effectiveEnd) {
            resolvedExpiryDate = new Date(parentContract.effectiveEnd);
          }
          if (!resolvedChannel) {
            resolvedChannel = parentContract.channelScope || 'All';
          }
        }
      }

      // Resolve calc_phase deterministically from the rule type so the
      // taxonomy is correct on insert (don't rely on the SQL default of
      // 'gross_calc' for non-gross rule types like minimum_guarantee or
      // deduction). Falls back to 'gross_calc' for unmapped types.
      // Also reject malformed taxonomy values up-front so junk never reaches
      // the DB and silently breaks engine ordering downstream.
      const {
        resolveCalcPhase: _resolvePhase,
        normalizeCalcPhase,
        normalizeTriggerSource,
        normalizeAggregationScope,
      } = await import('@shared/calcPhases.js');
      let resolvedCalcPhase: string;
      if (calcPhase !== undefined && calcPhase !== null && calcPhase !== '') {
        const normalized = normalizeCalcPhase(calcPhase);
        if (!normalized) {
          return res.status(400).json({ message: `Invalid calcPhase: ${calcPhase}` });
        }
        resolvedCalcPhase = normalized;
      } else {
        resolvedCalcPhase = _resolvePhase({ ruleType });
      }
      let resolvedTriggerSource = 'sale';
      if (triggerSource !== undefined && triggerSource !== null && triggerSource !== '') {
        const n = normalizeTriggerSource(triggerSource);
        if (!n) return res.status(400).json({ message: `Invalid triggerSource: ${triggerSource}` });
        resolvedTriggerSource = n;
      }
      // Aggregation scope: per_sale / per_period / per_contract.
      // Order of precedence:
      //   1. Caller-supplied aggregationScope (validated)
      //   2. Derived from formulaDefinition.aggregationPeriod
      //      (per_sale | monthly | quarterly | annual | contract)
      //   3. null — required for engine-aggregating rule types (validated below)
      let resolvedAggregationScope: string | null = null;
      if (aggregationScope !== undefined && aggregationScope !== null && aggregationScope !== '') {
        const n = normalizeAggregationScope(aggregationScope);
        if (!n) return res.status(400).json({ message: `Invalid aggregationScope: ${aggregationScope}` });
        resolvedAggregationScope = n;
      } else {
        const fd: any = formulaDefinition || {};
        resolvedAggregationScope = deriveAggregationScopeFromPeriod(fd?.aggregationPeriod);
      }
      // Aggregation period is mandatory for any rule whose calc engine
      // aggregates sales (percentage, tiered, per_unit, minimum_guarantee,
      // caps, etc.). Without it the engine silently falls back to per_sale,
      // which produces wrong results for quarterly / annual contracts.
      if (
        ruleTypeRequiresAggregationPeriod(ruleType) &&
        !resolvedAggregationScope &&
        !(formulaDefinition as any)?.aggregationPeriod
      ) {
        return res.status(400).json({
          message: 'Aggregation period is required for this rule type. Pick one in the Calculation section (per sale / monthly / quarterly / annual).',
          field: 'aggregationPeriod',
        });
      }

      // base_metric is meaningless for minimum_guarantee — the floor is a
      // dollar amount, not a rate against a sales field. Force NULL so the
      // editor's base-metric picker stays empty for these rules.
      const isMinGuarantee = String(ruleType).toLowerCase() === 'minimum_guarantee';
      const resolvedBaseMetric = isMinGuarantee ? null : (baseMetric || null);

      // Program (subtype_instance) is mandatory on every rule. If the caller
      // did not supply one, fall back to ensureDefaultSubtypeInstance() —
      // that auto-creates the contract's primary program if missing. Only
      // reject if even that cannot resolve a program (unmapped contract_type
      // / inactive subtype catalog), in which case the user must create one
      // manually before saving the rule.
      let resolvedSubtypeInstanceId: string | null = subtypeInstanceId || null;
      if (!resolvedSubtypeInstanceId) {
        try {
          const { ensureDefaultSubtypeInstance } = await import('./services/subtypeInstanceService');
          resolvedSubtypeInstanceId = await ensureDefaultSubtypeInstance(contractId);
        } catch (_e) {
          resolvedSubtypeInstanceId = null;
        }
      }
      if (!resolvedSubtypeInstanceId) {
        return res.status(400).json({
          message: 'Program is required. Pick a Program in the General section, or create a new one of the right type.',
          field: 'subtypeInstanceId',
        });
      }

      const [created] = await db.insert(contractRules).values({
        contractId,
        ruleType,
        ruleName,
        calcPhase: resolvedCalcPhase,
        triggerSource: resolvedTriggerSource,
        aggregationScope: resolvedAggregationScope,
        description: description || null,
        baseRate: baseRate || null,
        minimumGuarantee: minimumGuarantee || null,
        calculationFormula: calculationFormula || null,
        productCategories: productCategories || null,
        territories: territories || null,
        volumeTiers: volumeTiers || null,
        seasonalAdjustments: seasonalAdjustments || null,
        territoryPremiums: territoryPremiums || null,
        priority: priority || 10,
        clauseCategory: clauseCategory || 'general',
        customerSegments: customerSegments || null,
        partnerIds: partnerIds || null,
        channel: resolvedChannel,
        sourceSection: sourceSection || null,
        sourceText: sourceText || null,
        effectiveDate: resolvedEffectiveDate,
        expiryDate: resolvedExpiryDate,
        templateCode: templateCode || null,
        executionGroup: executionGroup || null,
        baseMetric: resolvedBaseMetric,
        confidence: confidence || null,
        milestones: milestones || null,
        milestoneCount: milestoneCount ? parseInt(milestoneCount) : null,
        milestoneTiers: milestoneTiers || null,
        milestoneConfig: milestoneConfig || null,
        // If the caller didn't pick a Program, ensure the contract has at least
        // one default Subtype Instance and auto-assign the rule to it. Keeps
        // the rule editor usable on contracts that pre-date the auto-provision
        // step or had it skipped (unmapped contract_type, etc.).
        subtypeInstanceId: await (async () => {
          if (subtypeInstanceId) return subtypeInstanceId;
          try {
            const { ensureDefaultSubtypeInstance } = await import('./services/subtypeInstanceService');
            return await ensureDefaultSubtypeInstance(contractId);
          } catch (e) {
            return null;
          }
        })(),
        formulaDefinition: formulaDefinition || null,
        isActive: true,
        reviewStatus: 'pending',
      }).returning();
      try {
        const { syncQualifiersFromRule } = await import("./services/qualifierSync");
        await syncQualifiersFromRule(created as any);
      } catch (syncErr) {
        console.error("[qualifierSync] create-from-rules-list sync failed:", syncErr);
      }
      try {
        const { revertContractApprovalIfRulesIncomplete } = await import("./services/contractApprovalIntegrity");
        await revertContractApprovalIfRulesIncomplete(contractId, `New rule '${(created as any).ruleName}' was added`);
      } catch (revertErr) {
        console.error("[contractApprovalIntegrity] add-rule revert failed:", revertErr);
      }
      res.json(created);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.put('/api/contract-rules/:ruleId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { ruleId } = req.params;
      const updates = { ...req.body };
      delete updates.id;
      delete updates.contractId;
      delete updates.createdAt;

      // Resolve the rule's contract id and enforce the edit lock.
      const [ruleForLock] = await db
        .select({ contractId: contractRules.contractId })
        .from(contractRules)
        .where(eq(contractRules.id, ruleId))
        .limit(1);
      if (ruleForLock?.contractId
        && (await enforceContractEditLock(req, res, ruleForLock.contractId))) {
        return;
      }
      // Approval lifecycle is owned by the dedicated approve/reject endpoints,
      // never by a generic rule edit. Strip these so a frontend that round-trips
      // the whole rule object (including approvalStatus: 'approved') cannot
      // accidentally preserve approval through a substance change.
      delete updates.approvalStatus;
      delete updates.approvedBy;
      delete updates.approvedAt;
      updates.updatedAt = new Date();
      const dateFields = ['effectiveDate', 'expiryDate', 'endDate', 'reviewedAt'];
      for (const field of dateFields) {
        if (updates[field] !== undefined) {
          updates[field] = updates[field] ? new Date(updates[field]) : null;
        }
      }
      // Auto-reset APPROVAL lifecycle when an already-approved rule is edited.
      // Verification (reviewStatus) is intentionally left alone — it answers
      // "is the AI extraction correct?" and survives content edits. Approval
      // answers "is this authorized for fee calculations?" and must be
      // re-granted whenever the rule's substance changes. The cascade to
      // revertContractApprovalIfRulesIncomplete below then re-opens the
      // contract approval gate.
      const editsRuleSubstance = Object.keys(updates).some(k =>
        !['updatedAt', 'reviewStatus', 'reviewedBy', 'reviewedAt', 'isActive'].includes(k)
      );
      const [existing] = await db.select().from(contractRules).where(eq(contractRules.id, ruleId)).limit(1);
      if (!existing) return res.status(404).json({ message: 'Rule not found' });
      // Phase taxonomy (Task #5 slice 1): when ruleType changes and the caller
      // did not explicitly supply calcPhase, re-derive it from the new ruleType
      // so the engine's phase ordering and persisted taxonomy stay correct.
      // Mirrors the recompute in PUT /api/contracts/:contractId/rules/:ruleId.
      const {
        resolveCalcPhase: _resolveCp,
        normalizeCalcPhase: _normCp,
        normalizeTriggerSource: _normTs,
        normalizeAggregationScope: _normAs,
      } = await import('@shared/calcPhases.js');
      // Empty string and null are explicitly invalid — never persist a blank
      // taxonomy value. Callers that want a default must omit the field.
      if (updates.calcPhase !== undefined) {
        const n = _normCp(updates.calcPhase);
        if (!n) return res.status(400).json({ message: `Invalid calcPhase: ${updates.calcPhase}` });
        updates.calcPhase = n;
      }
      if (updates.triggerSource !== undefined) {
        const n = _normTs(updates.triggerSource);
        if (!n) return res.status(400).json({ message: `Invalid triggerSource: ${updates.triggerSource}` });
        updates.triggerSource = n;
      }
      if (updates.aggregationScope !== undefined && updates.aggregationScope !== null && updates.aggregationScope !== '') {
        const n = _normAs(updates.aggregationScope);
        if (!n) return res.status(400).json({ message: `Invalid aggregationScope: ${updates.aggregationScope}` });
        updates.aggregationScope = n;
      }
      // Mirror the create path: derive aggregationScope from
      // formulaDefinition.aggregationPeriod when the caller did not supply it
      // explicitly, and require non-empty aggregationPeriod for any rule type
      // whose calc engine aggregates sales.
      const effectiveRuleType = (updates.ruleType || (existing as any).ruleType || '') as string;
      const incomingFormulaDef: any = updates.formulaDefinition !== undefined
        ? updates.formulaDefinition
        : (existing as any).formulaDefinition;
      const incomingAggPeriod = incomingFormulaDef?.aggregationPeriod;
      if (
        (updates.aggregationScope === undefined || updates.aggregationScope === null || updates.aggregationScope === '')
        && incomingAggPeriod
      ) {
        const derived = deriveAggregationScopeFromPeriod(incomingAggPeriod);
        if (derived) updates.aggregationScope = derived;
      }
      if (ruleTypeRequiresAggregationPeriod(effectiveRuleType)) {
        const finalAggScope = updates.aggregationScope !== undefined
          ? updates.aggregationScope
          : (existing as any).aggregationScope;
        if (!finalAggScope && !incomingAggPeriod) {
          return res.status(400).json({
            message: 'Aggregation period is required for this rule type. Pick one in the Calculation section (per sale / monthly / quarterly / annual).',
            field: 'aggregationPeriod',
          });
        }
      }
      // base_metric is meaningless for minimum_guarantee — force NULL to keep
      // the editor's base-metric picker honest and prevent stale 'net_sales'
      // values surviving a rule-type change into minimum_guarantee.
      if (String(effectiveRuleType).toLowerCase() === 'minimum_guarantee') {
        if (updates.baseMetric !== undefined || (existing as any).baseMetric) {
          updates.baseMetric = null;
        }
      }
      // Program (subtype_instance) is mandatory on every rule. Reject an
      // update that explicitly clears it, and reject a save that leaves the
      // rule with no program at all (existing rule with NULL program +
      // caller didn't supply one). Mirrors the create path.
      if (updates.subtypeInstanceId !== undefined) {
        if (!updates.subtypeInstanceId) {
          return res.status(400).json({
            message: 'Program is required. Pick a Program in the General section, or create a new one of the right type.',
            field: 'subtypeInstanceId',
          });
        }
      } else if (!(existing as any).subtypeInstanceId) {
        // Existing rule has no program (legacy / pre-mandatory data) and the
        // caller didn't supply one — auto-resolve to the contract's default
        // program so the save can succeed without surprising the user.
        try {
          const { ensureDefaultSubtypeInstance } = await import('./services/subtypeInstanceService');
          const auto = await ensureDefaultSubtypeInstance((existing as any).contractId);
          if (auto) {
            updates.subtypeInstanceId = auto;
          } else {
            return res.status(400).json({
              message: 'Program is required. Pick a Program in the General section, or create a new one of the right type.',
              field: 'subtypeInstanceId',
            });
          }
        } catch {
          return res.status(400).json({
            message: 'Program is required. Pick a Program in the General section, or create a new one of the right type.',
            field: 'subtypeInstanceId',
          });
        }
      }
      if (
        updates.ruleType
        && updates.ruleType !== (existing as any).ruleType
        && updates.calcPhase === undefined
      ) {
        updates.calcPhase = _resolveCp({ ruleType: updates.ruleType });
      }
      if (editsRuleSubstance) {
        if ((existing as any).approvalStatus === 'approved') {
          updates.approvalStatus = 'pending';
          updates.approvedBy = null;
          updates.approvedAt = null;
        }
        // Verification regression: editing the substance of a verified rule
        // means the human-confirmed extraction no longer matches the saved
        // values, so reviewStatus must drop back to under_review until a
        // reviewer re-verifies the new content.
        if ((existing as any).reviewStatus === 'verified'
            && updates.reviewStatus === undefined) {
          updates.reviewStatus = 'under_review';
          updates.reviewedBy = null;
          updates.reviewedAt = null;
        }
        // Mint a pending contract version (or append to the existing one)
        // BEFORE applying the rule edit, so the prior rule snapshot is captured
        // for discard.
        try {
          const { ensurePendingVersionForRuleEdit } = await import('./services/contractVersionMint');
          await ensurePendingVersionForRuleEdit(
            (existing as any).contractId,
            ruleId,
            req.user?.id || (existing as any).contractId,
            updates.ruleName || (existing as any).ruleName || 'Rule',
          );
        } catch (mintErr) {
          console.error('[contractVersionMint] PUT contract-rules mint failed:', mintErr);
        }
      }
      const [updated] = await db.update(contractRules)
        .set(updates)
        .where(eq(contractRules.id, ruleId))
        .returning();
      if (!updated) return res.status(404).json({ message: 'Rule not found' });
      try {
        const { syncQualifiersFromRule } = await import("./services/qualifierSync");
        await syncQualifiersFromRule(updated as any);
      } catch (syncErr) {
        console.error("[qualifierSync] update-contract-rules sync failed:", syncErr);
      }
      try {
        const { revertContractApprovalIfRulesIncomplete } = await import("./services/contractApprovalIntegrity");
        await revertContractApprovalIfRulesIncomplete((updated as any).contractId, `Rule '${(updated as any).ruleName}' was edited`);
      } catch (revertErr) {
        console.error("[contractApprovalIntegrity] update-contract-rules revert failed:", revertErr);
      }
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.patch('/api/contract-rules/:ruleId/review-status', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { ruleId } = req.params;
      const { reviewStatus, notes } = req.body;
      const validStatuses = ['pending', 'under_review', 'verified', 'rejected'];
      if (!validStatuses.includes(reviewStatus)) {
        return res.status(400).json({ message: `Invalid review status. Must be one of: ${validStatuses.join(', ')}` });
      }
      const [ruleParent] = await db.select({ contractId: contractRules.contractId })
        .from(contractRules).where(eq(contractRules.id, ruleId));
      if (ruleParent && await sendIfLocked(res, ruleParent.contractId)) return;
      // Gate: cannot mark a rule "verified" while it has unmapped reference values.
      if (reviewStatus === 'verified') {
        try {
          const unmapped = await findUnmappedRefsForRule(ruleId);
          if (unmapped.length > 0) {
            return res.status(400).json({
              error: 'unmapped_references',
              message: `Resolve unmapped references first: ${unmapped.join(', ')}`,
              unmapped,
            });
          }
        } catch (gateErr) {
          console.error('[review-status] unmapped check failed:', gateErr);
          // Don't block on internal error — fall through.
        }
      }
      const updateData: any = {
        reviewStatus,
        reviewedBy: req.user?.id || null,
        reviewedAt: new Date(),
        updatedAt: new Date(),
      };
      if (notes) {
        updateData.validationDetails = { notes, updatedAt: new Date().toISOString(), updatedBy: req.user?.username || 'unknown' };
      }
      const [updated] = await db.update(contractRules)
        .set(updateData)
        .where(eq(contractRules.id, ruleId))
        .returning();
      if (!updated) return res.status(404).json({ message: 'Rule not found' });
      res.json(updated);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.delete('/api/contract-rules/:ruleId', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { ruleId } = req.params;
      const [existing] = await db.select().from(contractRules).where(eq(contractRules.id, ruleId)).limit(1);
      if (existing) {
        try {
          const { cascadeDeleteQualifiersForRule } = await import("./services/qualifierSync");
          await cascadeDeleteQualifiersForRule(existing as any);
        } catch (syncErr) {
          console.error("[qualifierSync] delete-contract-rules cascade failed:", syncErr);
        }
      }
      await db.delete(contractRules).where(eq(contractRules.id, ruleId));
      if (existing) {
        try {
          const { revertContractApprovalIfRulesIncomplete } = await import("./services/contractApprovalIntegrity");
          await revertContractApprovalIfRulesIncomplete((existing as any).contractId, `Rule '${(existing as any).ruleName}' was deleted`);
        } catch (revertErr) {
          console.error("[contractApprovalIntegrity] delete-contract-rules revert failed:", revertErr);
        }
      }
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // ====== Subtype Instances + Policies (Round 2 UI) ======
  // List all Subtype Instances for a contract.
  app.get('/api/contracts/:contractId/subtype-instances', isAuthenticated, async (req: any, res: Response) => {
    try {
      const { listInstancesForContract } = await import('./services/policiesService');
      const rows = await listInstancesForContract(req.params.contractId);
      res.json(rows);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Catalog of subtype types ("Programs"). With ?contractId= the list is
  // filtered through the flow_subtype_validity matrix to only the subtypes
  // valid for that contract's flow type (with the matrix-primary one first
  // and isPrimary=true). Without ?contractId= returns the full active catalog.
  app.get('/api/subtypes', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.query?.contractId ? String(req.query.contractId) : '';
      if (contractId) {
        const { getAllowedSubtypesForContract } = await import('./services/subtypeInstanceService');
        const rows = await getAllowedSubtypesForContract(contractId);
        return res.json(rows);
      }
      const r = await db.execute(sql`
        SELECT code, name, description, false AS is_primary
        FROM subtypes
        WHERE is_active = true
        ORDER BY name ASC
      `);
      res.json(((r as any).rows || []).map((row: any) => ({
        code: row.code,
        name: row.name,
        description: row.description,
        isPrimary: false,
      })));
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // -------- Subtype CATALOG admin (Contract Reference Lookups page) --------
  // List ALL subtypes (including inactive) for the admin UI. The /api/subtypes
  // GET above is intentionally restricted to active rows + matrix-aware
  // filtering for end users.
  app.get('/api/subtypes/admin', isAuthenticated, async (req: any, res: Response) => {
    try {
      const r = await db.execute(sql`
        SELECT id, code, name, description, category,
               default_aggregation_period AS "defaultAggregationPeriod",
               default_engine_handler AS "defaultEngineHandler",
               default_gl_account AS "defaultGlAccount",
               default_finance_hub_tab AS "defaultFinanceHubTab",
               is_active AS "isActive", sort_order AS "sortOrder",
               created_at AS "createdAt", updated_at AS "updatedAt"
        FROM subtypes
        ORDER BY category ASC, sort_order ASC, code ASC
      `);
      res.json((r as any).rows || []);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  app.post('/api/subtypes/admin', isAuthenticated, async (req: any, res: Response) => {
    if (!isSystemAdmin(req.user) && !isContextAdmin(req.user)) return res.status(403).json({ error: 'Admin access required' });
    try {
      const code = String(req.body?.code || '').trim().toUpperCase();
      const name = String(req.body?.name || '').trim();
      const category = String(req.body?.category || 'financial').trim().toLowerCase();
      if (!code || !name) return res.status(400).json({ message: 'code and name are required' });
      if (!['financial', 'operational'].includes(category)) {
        return res.status(400).json({ message: "category must be 'financial' or 'operational'" });
      }
      const description = req.body?.description ? String(req.body.description) : null;
      const ins = await db.execute(sql`
        INSERT INTO subtypes (code, name, description, category, is_active)
        VALUES (${code}, ${name}, ${description}, ${category}, true)
        RETURNING id, code, name, description, category, is_active AS "isActive"
      `);
      res.status(201).json((ins as any).rows?.[0]);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.put('/api/subtypes/admin/:id', isAuthenticated, async (req: any, res: Response) => {
    if (!isSystemAdmin(req.user) && !isContextAdmin(req.user)) return res.status(403).json({ error: 'Admin access required' });
    try {
      const id = req.params.id;
      const name = req.body?.name != null ? String(req.body.name) : null;
      const description = req.body?.description != null ? String(req.body.description) : null;
      const category = req.body?.category != null ? String(req.body.category).toLowerCase() : null;
      const isActive = req.body?.isActive != null ? Boolean(req.body.isActive) : null;
      const r = await db.execute(sql`
        UPDATE subtypes SET
          name = COALESCE(${name}, name),
          description = COALESCE(${description}, description),
          category = COALESCE(${category}, category),
          is_active = COALESCE(${isActive}, is_active),
          updated_at = NOW()
        WHERE id = ${id}
        RETURNING id, code, name, description, category, is_active AS "isActive"
      `);
      const row = (r as any).rows?.[0];
      if (!row) return res.status(404).json({ message: 'Subtype not found' });
      res.json(row);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  app.delete('/api/subtypes/admin/:id', isAuthenticated, async (req: any, res: Response) => {
    if (!isSystemAdmin(req.user)) return res.status(403).json({ error: 'System admin access required' });
    try {
      // Refuse if any subtype_instances exist for this subtype (data safety)
      const codeRow = await db.execute(sql`SELECT code FROM subtypes WHERE id = ${req.params.id} LIMIT 1`);
      const code = (codeRow as any).rows?.[0]?.code;
      if (!code) return res.status(404).json({ message: 'Subtype not found' });
      const used = await db.execute(sql`SELECT COUNT(*)::int AS n FROM subtype_instances WHERE subtype_code = ${code}`);
      const n = Number((used as any).rows?.[0]?.n || 0);
      if (n > 0) {
        return res.status(409).json({
          message: `Cannot delete subtype '${code}' — ${n} program instance(s) reference it. Deactivate it instead.`,
        });
      }
      await db.execute(sql`DELETE FROM subtypes WHERE id = ${req.params.id}`);
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // -------- Flow × Subtype VALIDITY MATRIX admin --------
  // Returns the full matrix as a flat list of { flowTypeCode, subtypeCode,
  // isPrimary, notes }. The Reference Lookups UI pivots this into a 2-D grid.
  app.get('/api/flow-subtype-validity', isAuthenticated, async (req: any, res: Response) => {
    try {
      const r = await db.execute(sql`
        SELECT id,
               flow_type_code AS "flowTypeCode",
               subtype_code AS "subtypeCode",
               is_primary AS "isPrimary",
               notes
        FROM flow_subtype_validity
        ORDER BY flow_type_code ASC, subtype_code ASC
      `);
      res.json((r as any).rows || []);
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Idempotent upsert: if a (flow, subtype) pair exists, update isPrimary/notes;
  // otherwise insert. Used when the admin toggles a checkbox.
  app.post('/api/flow-subtype-validity', isAuthenticated, async (req: any, res: Response) => {
    if (!isSystemAdmin(req.user) && !isContextAdmin(req.user)) return res.status(403).json({ error: 'Admin access required' });
    try {
      const flowTypeCode = String(req.body?.flowTypeCode || '').trim();
      const subtypeCode = String(req.body?.subtypeCode || '').trim();
      const isPrimary = Boolean(req.body?.isPrimary);
      const notes = req.body?.notes ? String(req.body.notes) : null;
      if (!flowTypeCode || !subtypeCode) {
        return res.status(400).json({ message: 'flowTypeCode and subtypeCode are required' });
      }
      // If marking primary, demote any other primary for this flow type first
      if (isPrimary) {
        await db.execute(sql`
          UPDATE flow_subtype_validity SET is_primary = false
          WHERE flow_type_code = ${flowTypeCode} AND subtype_code <> ${subtypeCode}
        `);
      }
      const r = await db.execute(sql`
        INSERT INTO flow_subtype_validity (flow_type_code, subtype_code, is_primary, notes)
        VALUES (${flowTypeCode}, ${subtypeCode}, ${isPrimary}, ${notes})
        ON CONFLICT (flow_type_code, subtype_code)
        DO UPDATE SET is_primary = EXCLUDED.is_primary, notes = EXCLUDED.notes
        RETURNING id, flow_type_code AS "flowTypeCode", subtype_code AS "subtypeCode",
                  is_primary AS "isPrimary", notes
      `);
      res.json((r as any).rows?.[0]);
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

  // Delete a validity row (un-check the matrix cell)
  app.delete('/api/flow-subtype-validity', isAuthenticated, async (req: any, res: Response) => {
    if (!isSystemAdmin(req.user) && !isContextAdmin(req.user)) return res.status(403).json({ error: 'Admin access required' });
    try {
      const flowTypeCode = String(req.query?.flowTypeCode || req.body?.flowTypeCode || '').trim();
      const subtypeCode = String(req.query?.subtypeCode || req.body?.subtypeCode || '').trim();
      if (!flowTypeCode || !subtypeCode) {
        return res.status(400).json({ message: 'flowTypeCode and subtypeCode are required' });
      }
      await db.execute(sql`
        DELETE FROM flow_subtype_validity
        WHERE flow_type_code = ${flowTypeCode} AND subtype_code = ${subtypeCode}
      `);
      res.json({ success: true });
    } catch (error: any) {
      res.status(500).json({ message: error.message });
    }
  });

  // Create a new subtype_instance ("Program") on a contract. Body:
  //   { subtypeCode: string, label?: string }
  // The label defaults to "{counterparty|contract#} — {subtype name}". The
  // contract may have multiple instances of the same subtype, so this is NOT
  // gated by the existing-instance check that ensureDefaultSubtypeInstance
  // uses — that helper is for the auto-default; this endpoint is for explicit
  // user-driven creation from the rule editor.
  app.post('/api/contracts/:contractId/subtype-instances', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.contractId;
      const subtypeCode = String(req.body?.subtypeCode || '').trim();
      const userLabel = req.body?.label ? String(req.body.label).trim() : '';
      if (!subtypeCode) {
        return res.status(400).json({ message: 'subtypeCode is required' });
      }

      const subRes = await db.execute(sql`
        SELECT name FROM subtypes WHERE code = ${subtypeCode} AND is_active = true LIMIT 1
      `);
      if (!(subRes as any).rows || (subRes as any).rows.length === 0) {
        return res.status(400).json({ message: `Unknown or inactive subtype code: ${subtypeCode}` });
      }
      const subtypeName = ((subRes as any).rows[0] as any).name as string;

      const cRes = await db.execute(sql`
        SELECT counterparty_name, contract_number FROM contracts WHERE id = ${contractId} LIMIT 1
      `);
      if (!(cRes as any).rows || (cRes as any).rows.length === 0) {
        return res.status(404).json({ message: 'Contract not found' });
      }
      const c = (cRes as any).rows[0] as any;
      const prefix =
        (c.counterparty_name && String(c.counterparty_name).trim()) ||
        (c.contract_number && String(c.contract_number).trim()) ||
        'Default';
      const label = userLabel || `${prefix} — ${subtypeName}`;

      const ins = await db.execute(sql`
        INSERT INTO subtype_instances (contract_id, subtype_code, label, status)
        VALUES (${contractId}, ${subtypeCode}, ${label}, 'active')
        RETURNING id, contract_id, subtype_code, label, status, created_at, updated_at
      `);
      const row = (ins as any).rows?.[0];
      res.status(201).json({
        id: row.id,
        contractId: row.contract_id,
        subtypeCode: row.subtype_code,
        subtypeName,
        label: row.label,
        status: row.status,
        createdAt: row.created_at,
        updatedAt: row.updated_at,
      });
    } catch (error: any) {
      console.error('Error creating subtype instance:', error);
      res.status(500).json({ message: error.message });
    }
  });

