      const allowed = ['aggregationPeriod', 'obligationAccrualBasis', 'glAccount', 'financeHubTab', 'releaseTriggerType', 'notes'];
      const patch: any = {};
      for (const k of allowed) if (k in (req.body ?? {})) patch[k] = req.body[k];
      const next = await updateAccrualPolicyVersioned(req.params.id, patch, req.user?.id);
