  // Update settlement policy + any of the 5 children atomically (versioned).
  app.patch('/api/subtype-instances/:id/settlement-policy', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = await _contractIdForInstance(req.params.id);
      const { sendIfLocked } = await import('./services/contractEditLock');
      if (await sendIfLocked(res, contractId)) return;
      const { updateSettlementPolicyVersioned } = await import('./services/policiesService');
      const body = req.body ?? {};
      // Whitelist editable fields per child to keep the client from
      // touching version/audit/FK columns.
      const policyAllowed = ['notes'];
      const psAllowed = ['cadence', 'paymentTermsDays', 'paymentDay', 'trueUpCadence', 'notes'];
      const smAllowed = ['method', 'bankAccountRef', 'remitToParty', 'notes'];
      const ohAllowed = ['strategy', 'thresholdAmount', 'notes'];
      const dhAllowed = ['defaultStrategy', 'responseSlaDays', 'escalationContact', 'notes'];
      const fxAllowed = ['rateSource', 'fixedRate', 'baseCurrency', 'notes'];

      const pick = (src: any, allowed: string[]) => {
        if (!src || typeof src !== 'object') return undefined;
        const out: any = {};
        for (const k of allowed) if (k in src) out[k] = src[k];
        return Object.keys(out).length ? out : undefined;
      };

      const patch = {
        policy: pick(body.policy, policyAllowed),
        paymentSchedule: pick(body.paymentSchedule, psAllowed),
        settlementMethod: pick(body.settlementMethod, smAllowed),
        overpaymentHandling: pick(body.overpaymentHandling, ohAllowed),
        disputeHandling: pick(body.disputeHandling, dhAllowed),
        fxRule: pick(body.fxRule, fxAllowed),
      };

      const newPolicyId = await updateSettlementPolicyVersioned(req.params.id, patch, req.user?.id);
      // Return the freshly-created policy + children for cache hydration.
      const { getCurrentSettlementPolicy } = await import('./services/policiesService');
      const fresh = await getCurrentSettlementPolicy(req.params.id);
      res.json({ newPolicyId, ...fresh });
    } catch (error: any) {
      res.status(400).json({ message: error.message });
    }
  });

