  // Retroactively generate structured data for existing analyzed contracts
  app.post('/api/contracts/:id/generate-structured-data', isAuthenticated, async (req: any, res: Response) => {
    try {
      const contractId = req.params.id;
      
      const contract = await storage.getContract(contractId);
      if (!contract) {
        return res.status(404).json({ message: 'Contract not found' });
      }

      const existingTerms = await db.select().from(contractTermsTable).where(eq(contractTermsTable.contractId, contractId)).limit(1);
      if (existingTerms.length > 0) {
        return res.json({ message: 'Structured data already exists', skipped: true });
      }

      const rules = await db.select().from(contractRules).where(eq(contractRules.contractId, contractId)).orderBy(contractRules.extractionOrder);
      
      const analysis = contract.analysis as any;
      const keyTerms = (contract as any).keyTerms as any;
      const parties = keyTerms || {};
      const licensor = parties.licensor || contract.counterpartyName || '';
      const licensee = parties.licensee || '';
      const effectiveDateStr = contract.effectiveStart ? contract.effectiveStart.toISOString().split('T')[0] : null;
      const expirationDateStr = contract.effectiveEnd ? contract.effectiveEnd.toISOString().split('T')[0] : null;

      const parseSimpleDate = (dateStr: string | null): Date | null => {
        if (!dateStr) return null;
        try {
          const m = dateStr.match(/^(\d{4})-(\d{2})-(\d{2})$/);
          if (m) return new Date(Date.UTC(parseInt(m[1]), parseInt(m[2]) - 1, parseInt(m[3]), 12, 0, 0));
          return null;
        } catch { return null; }
      };

      const effectiveDateParsed = parseSimpleDate(effectiveDateStr) || contract.effectiveStart || null;
      const expirationDateParsed = parseSimpleDate(expirationDateStr) || contract.effectiveEnd || null;

      await db.update(contracts).set({
        owningParty: licensor || null,
        counterpartyType: licensee || null,
        contractStatus: 'Draft',
        currency: (keyTerms as any)?.currency || 'USD',
      }).where(eq(contracts.id, contractId));

      let termsCount = 0;
      let qualifiersCount = 0;
      for (let idx = 0; idx < rules.length; idx++) {
        const rule = rules[idx];
        const termId = crypto.randomUUID();
        const formulaDef = rule.formulaDefinition as any;

        let tierMinVal: string | null = null;
        let paymentTimingVal: string | null = null;
        try {
          const calc = (rule.formulaDefinition as any)?.calculation || {};
          if ((rule.ruleType === 'minimum_guarantee' || rule.ruleType === 'minimum-guarantee') && calc.amount != null) {
            tierMinVal = String(calc.amount);
          }
          if (rule.ruleType === 'payment_schedule' || rule.ruleType === 'payment-schedule') {
            const parts: string[] = [];
            if (calc.paymentFrequency) parts.push(String(calc.paymentFrequency));
            if (calc.paymentDueDays != null) parts.push(`net ${calc.paymentDueDays} days`);
            if (parts.length > 0) paymentTimingVal = parts.join(' · ');
          }
        } catch { /* ignore malformed formula */ }

        await db.insert(contractTermsTable).values({
          termId,
          contractId,
          termSequence: idx + 1,
          termName: rule.ruleName || `Rule ${idx + 1}`,
          termType: rule.ruleType || 'percentage',
          rateValue: rule.baseRate ? String(rule.baseRate) : null,
          tierMin: tierMinVal,
          paymentTiming: paymentTimingVal,
          appliesToProductCategory: rule.productCategories ? (rule.productCategories as string[]).join(', ') : null,
          appliesToTerritory: rule.territories ? (rule.territories as string[]).join(', ') : null,
          effectiveDate: effectiveDateParsed,
          linkedRuleId: rule.id,
        });
        termsCount++;

        const prodCats = rule.productCategories as string[] | null;
        const territories = rule.territories as string[] | null;
        const ruleClauseId = (rule as any).sourceClauseId || null;
        if (prodCats && prodCats.length > 0) {
          for (const category of prodCats) {
            await db.insert(contractQualifiersTable).values({
              qualifierId: crypto.randomUUID(),
              termId,
              contractId,
              contractClauseId: ruleClauseId,
              qualifierType: 'inclusion',
              qualifierField: 'product_category',
              operator: 'in',
              qualifierValue: category,
            });
            qualifiersCount++;
          }
        }
        if (territories && territories.length > 0) {
          for (const territory of territories) {
            await db.insert(contractQualifiersTable).values({
              qualifierId: crypto.randomUUID(),
              termId,
              contractId,
              contractClauseId: ruleClauseId,
              qualifierType: 'inclusion',
              qualifierField: 'territory',
              operator: 'in',
              qualifierValue: territory,
            });
            qualifiersCount++;
          }
        }
      }

      let partnersCount = 0;
      // Resolve raw extracted names against partner_master so partner_id
      // gets a real master id (or NULL) — never raw text — and link_status
      // reflects the actual match. Putting raw text into partner_id makes
      // the Parties tab badge look "Manual 0%" for AI-extracted parties.
      const { resolvePartnerLink: _resolveLinkRetro } = await import('./services/masterDataLinker');
      const _retroInsert = async (rawName: string, kind: 'licensor' | 'licensee') => {
        const link = await _resolveLinkRetro(rawName, contract.companyId);
        await db.insert(contractPartnerAssignmentsTable).values({
          assignmentId: crypto.randomUUID(),
          contractId,
          partnerId: link.resolvedId,
          partyKind: 'partner',
          partyRole: kind === 'licensor' ? 'owning_party' : 'counterparty',
          assignmentType: kind,
          effectiveStart: effectiveDateParsed,
          effectiveEnd: expirationDateParsed,
          status: 'active',
          isPrimary: true,
          rawValue: rawName,
          linkStatus: link.status,
          linkConfidence: link.confidence ?? null,
          linkMethod: link.method,
        });
      };
      if (licensor) { await _retroInsert(licensor, 'licensor'); partnersCount++; }
      if (licensee) { await _retroInsert(licensee, 'licensee'); partnersCount++; }

      console.log(`✅ Retroactive structured data generated for contract ${contractId}: terms=${termsCount}, qualifiers=${qualifiersCount}, partners=${partnersCount}`);
      res.json({ 
        success: true, 
        contractId,
        termsCount,
        qualifiersCount,
        partnersCount,
      });
    } catch (error: any) {
      console.error(`❌ Failed to generate structured data:`, error.message);
      res.status(500).json({ message: error.message });
    }
  });

